BEGIN;
UPDATE decision_nodes SET body = E'**This is NOT true hyponatremia.** The measured sodium is low but total body water and sodium balance may be normal.\n\n**Translocational (elevated osm):**\n• Hyperglycemia — correct Na+ by adding **1.6 mEq/L for every 100 mg/dL glucose above 100** (use 2.4 mEq/L if glucose >400)\n• Mannitol, IV contrast, glycine (TURP syndrome)\n• Treatment: correct the underlying osmole\n\n**Pseudohyponatremia (normal osm):**\n• Severe hyperlipidemia (triglycerides >1500)\n• Paraproteinemia (myeloma, Waldenström)\n• Confirm with **point-of-care sodium** (direct ISE, not affected by protein/lipid interference)\n• Treatment: treat the underlying condition\n\n[Non-Hypotonic Hyponatremia](#/info/na-non-hypotonic-info)' WHERE id = 'na-non-hypotonic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine osmolality determines whether ADH (vasopressin) is active.\n\n**Urine Osm < 100 mOsm/kg** — ADH is appropriately suppressed. The kidney is maximally diluting urine. The problem is **excessive water intake or inadequate solute intake** overwhelming the kidney’s diluting capacity.\n\n**Urine Osm > 100 mOsm/kg** — ADH is active (either appropriately or inappropriately). The kidney is concentrating urine when it should be diluting. Proceed to urine sodium to differentiate causes.' WHERE id = 'na-hypo-urine-osm' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**ADH is suppressed — the kidney is doing its job.** The problem is excessive free water intake or severely low solute intake overwhelming diluting capacity (~20 L/day max).\n\n**Causes:**\n• **Primary polydipsia** — psychiatric patients, often on medications that cause dry mouth\n• **Beer potomania** — low-solute diet (beer has minimal protein/electrolytes, so minimal obligate solute excretion)\n• **Tea-and-toast diet** — elderly with inadequate protein/salt intake\n• **Marathon/exercise-associated hyponatremia** — excess hypotonic fluid intake during exercise\n\n**HIGH overcorrection risk.** Once water intake is restricted, the kidney rapidly excretes free water (no ADH to stop it). Na+ can rise dangerously fast.\n\n**Management:**\n• Restrict free water intake\n• For beer potomania/low solute: [Oral Urea](#/drug/oral-urea/siad) 15-30g PO daily to increase obligate water excretion\n• **Proactive DDAVP clamp** strongly recommended: [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) 2 mcg IV q6-8h to prevent uncontrolled water excretion\n• [DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — full protocol\n• Check Na+ every 2 hours — do NOT allow >8-10 mEq/L rise in 24 hours\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) if overcorrecting' WHERE id = 'na-hypo-water-excess' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine sodium differentiates **renal sodium losses** from **extrarenal losses** in the setting of ADH-mediated hyponatremia.\n\n**Urine Na < 30 mEq/L** — The kidney is retaining sodium. Volume depletion (hypovolemic) or edematous states (hypervolemic) with reduced effective arterial blood volume.\n\n**Urine Na > 30 mEq/L** — The kidney is wasting sodium. SIAD, diuretics, adrenal insufficiency, cerebral salt wasting, or renal failure.\n\n**Caveat:** Diuretics can raise urine Na even in hypovolemic patients. Check urine Na **before** or >48 hours after last diuretic dose if possible.' WHERE id = 'na-hypo-urine-na' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'The kidney is retaining sodium, indicating **reduced effective circulating volume.** The key distinction is between true hypovolemia and hypervolemic states with reduced effective arterial blood volume.\n\n**Hypovolemic (dry):**\n• GI losses (vomiting, diarrhea)\n• Third-spacing (pancreatitis, burns)\n• Diaphoresis, insensible losses\n• Clinical: tachycardia, orthostatic hypotension, poor skin turgor, dry mucous membranes\n\n**Hypervolemic (edematous):**\n• Heart failure\n• Cirrhosis\n• Nephrotic syndrome\n• Clinical: peripheral edema, ascites, JVD, pulmonary rales' WHERE id = 'na-hypo-low-una' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Immediate treatment for severe symptomatic hyponatremia** (seizures, coma, respiratory distress).\n\n[3% Hypertonic Saline](#/drug/hypertonic-saline/severe symptomatic) **100-150 mL IV bolus over 10-20 minutes.** Repeat up to 2 additional times (total 3 boluses) if severe symptoms persist.\n\n**Target:** Raise Na+ by **4-6 mEq/L** in the first 1-2 hours — this is sufficient to reverse cerebral edema and stop seizures. Each 100 mL bolus of 3% NaCl raises Na+ approximately **2 mEq/L** in a 70 kg adult.\n\n**Peripheral access is acceptable for boluses** — do NOT delay treatment for central line placement. Central access is preferred only for continuous infusions.\n\n**SALSA Trial (2021):** Bolus 3% NaCl was noninferior to continuous infusion for symptomatic hyponatremia, with lower overcorrection rates.\n\n**Give empirically:** [Thiamine](#/drug/thiamine/hyponatremia) **100 mg IV** now if not already given — thiamine deficiency increases ODS risk.\n\n**After stabilization:** Recheck Na+ at 1 hour. If symptoms improved, proceed to correction limits.' WHERE id = 'na-hypo-emergency' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Overcorrection causes osmotic demyelination syndrome (ODS)** — a devastating and often irreversible pontine and extrapontine injury.\n\n**Maximum correction rates:**\n• **Standard risk:** ≤10 mEq/L in first 24 hours, ≤18 mEq/L in 48 hours\n• **High risk for ODS:** ≤8 mEq/L in first 24 hours\n\n[ODS Risk Factors](#/info/na-ods-risk) — high-risk populations include: Na+ ≤105, alcohol use disorder, liver disease, malnutrition, hypokalemia, thiamine deficiency\n\n**Key principle:** The goal is to correct enough to stop symptoms (4-6 mEq/L rise), then **slow down.** The acute danger is cerebral edema; the correction danger is ODS.\n\n**If overcorrecting** (Na+ rising faster than target):\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) — [Desmopressin (DDAVP)](#/drug/desmopressin/overcorrection rescue) 2 mcg IV stat + D5W 3 mL/kg/hr to lower Na+ back to safe trajectory\n\n**Monitor:** Check Na+ every 2 hours during active correction. Use a tracking sheet to plot the correction trajectory.\n\n**Concurrent potassium correction counts toward sodium correction** — if you give 40 mEq KCl, expect Na+ to rise ~1 mEq/L as K+ enters cells and Na+ exits.' WHERE id = 'na-hypo-correction-limits' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'The **DDAVP clamp** (also called "proactive DDAVP" or "DDAVP clamp-and-bolus") is the safest approach to controlled sodium correction.\n\n**How it works:** DDAVP locks the kidneys in a maximally concentrating state (prevents free water excretion). This gives the clinician **complete control** over the correction rate — Na+ rises only from administered hypertonic saline boluses, not from unpredictable renal water excretion.\n\n[DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — full initiation and monitoring protocol\n\n**Strongest indications for proactive clamp:**\n• Na+ ≤120 mEq/L\n• High ODS risk (alcoholism, liver disease, malnutrition)\n• Reversible cause likely to self-correct (hypovolemia, diuretics, beer potomania)\n• Any situation where overcorrection would be catastrophic' WHERE id = 'na-hypo-ddavp-decision' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Step 1 — Lock the kidneys:**\n[Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) **2 mcg IV q6-8h** (schedule doses around the clock). This prevents all renal free water excretion.\n\n**Step 2 — Controlled bolus correction:**\n[3% Hypertonic Saline](#/drug/hypertonic-saline/ddavp clamp bolus) **100 mL IV bolus** — each bolus raises Na+ approximately **2 mEq/L** in a 70 kg adult. Give boluses every 4-6 hours as needed to achieve target correction rate.\n\n**Step 3 — Monitor:**\n• Check Na+ **every 2 hours** during active clamp\n• Track cumulative 24-hour correction on a flow sheet\n• Target: 4-6 mEq/L rise in first 24 hours for high-risk patients, up to 10 mEq/L for standard risk\n\n**Step 4 — Discontinue clamp:**\n• Once Na+ >125 mEq/L and underlying cause addressed\n• Taper: extend DDAVP interval to q12h for 24 hours, then stop\n• Continue monitoring Na+ q4-6h for 24 hours after stopping DDAVP\n\n**If Na+ rises too fast despite clamp:** Confirm DDAVP dosing is adequate (urine Osm should be >500). Give **D5W 3 mL/kg/hr** to actively lower Na+ back to safe trajectory.\n\n[DDAVP Clamp-Bolus Protocol](#/info/na-ddavp-clamp) — expanded protocol with discontinuation guidance' WHERE id = 'na-hypo-ddavp-protocol' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Urine Na >30 mEq/L with ADH-mediated hyponatremia. The kidney is actively wasting sodium. The three main causes are:\n\n**SIAD (Syndrome of Inappropriate Antidiuresis):**\n• Most common cause of euvolemic hyponatremia\n• Euvolemic on exam, urine Osm >100, urine Na >30, low uric acid\n• [SIAD Causes & Diagnosis](#/info/na-siad-causes) — medications, malignancy, neurologic, pulmonary\n\n**Diuretic-induced:**\n• Thiazides >> loops (thiazides impair dilution; loops impair concentration)\n• May have UNa >30 despite being volume depleted\n• Check urine Na 48 hours after holding diuretic — if still >30, not solely diuretic\n\n**Adrenal insufficiency:**\n• Primary (Addison) or secondary (pituitary)\n• Cortisol is a tonic inhibitor of ADH — deficiency → unopposed ADH secretion\n• Check AM cortisol and ACTH' WHERE id = 'na-hypo-high-una' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**First-line: Fluid restriction**\n• Restrict to 800-1000 mL/day total fluid intake\n• Effective only if urine Osm < 500 AND urine Osm/serum Osm ratio < 1.0\n• If ratio >1.0, every mL of urine excretes more water than intake replaces — fluid restriction will fail\n\n**Second-line: Oral urea**\n[Oral Urea](#/drug/oral-urea/siad) **15-30g PO daily** (titrate up to 60g/day). Creates obligate osmotic diuresis. Bitter taste — mix with orange juice or cola. Ure-Na brand designed for palatability.\n\n**Third-line: Salt tabs + loop diuretic**\n[Sodium Chloride Tablets](#/drug/nacl-tablets/siad) **1-3g PO TID** + [Furosemide](#/drug/furosemide/siad) **20-40 mg PO daily**. The loop diuretic impairs urinary concentration (breaks the medullary gradient), and salt tabs replace renal sodium losses.\n\n**NOT recommended: Vaptans** (tolvaptan, conivaptan). Unpredictable overcorrection risk, hepatotoxicity, expensive, no mortality benefit. European guidelines and IBCC explicitly recommend against.\n\n**Treat the underlying cause:** Discontinue offending medication (SSRIs, carbamazepine, NSAIDs, opioids). Evaluate for occult malignancy if no obvious cause identified. [SIAD Causes & Diagnosis](#/info/na-siad-causes)' WHERE id = 'na-siad-treatment' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Thiazide diuretics are the most common medication cause of hyponatremia.** Typically occurs within 2 weeks of initiation, especially in elderly women with low body mass.\n\n**Mechanism:** Thiazides impair the kidney’s diluting segment (distal convoluted tubule) while preserving the concentrating segment. Loops do the opposite — they impair concentration, which is why loop diuretics rarely cause severe hyponatremia and are even used to treat SIAD.\n\n**Management:**\n• **Hold the thiazide immediately** — never rechallenge\n• Replace volume deficit with normal saline if hypovolemic\n• Check and correct potassium and magnesium\n\n**HIGH overcorrection risk.** Once the thiazide is discontinued and volume is restored, the kidney rapidly excretes free water (ADH suppresses, diluting segment recovers). Na+ can rise 15-20 mEq/L in 24 hours without intervention.\n\n• **If Na+ <120:** Proactive [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) clamp strongly recommended\n• Check Na+ every 2 hours for at least 24 hours after holding the diuretic\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) if Na+ rising too fast' WHERE id = 'na-hypo-diuretic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Cortisol deficiency causes hyponatremia through two mechanisms:**\n• Cortisol tonically inhibits ADH — deficiency leads to unopposed ADH secretion\n• Reduced cardiac output and GFR → nonosmotic ADH release\n\n**Diagnosis:**\n• AM cortisol <3 mcg/dL → virtually diagnostic\n• AM cortisol 3-18 mcg/dL → cosyntropin stimulation test\n• AM cortisol >18 mcg/dL → AI unlikely\n• Check ACTH to distinguish primary (high ACTH) from secondary (low ACTH)\n\n**If hemodynamically unstable:**\n• **Stress-dose hydrocortisone 100 mg IV** immediately — do NOT wait for cortisol results\n• Then 50 mg IV q8h until stable\n• Normal saline for volume resuscitation\n\n**If stable:**\n• Draw cortisol/ACTH, then start hydrocortisone 20 mg AM / 10 mg PM\n• Na+ corrects as cortisol is replaced\n• Monitor for overcorrection — ADH suppresses once cortisol is adequate' WHERE id = 'na-hypo-adrenal' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Volume depletion triggers nonosmotic ADH release** — the body prioritizes volume over tonicity. ADH retains free water, diluting sodium.\n\n**Common causes:**\n• GI losses (vomiting, diarrhea, NG suction)\n• Third-spacing (pancreatitis, burns, bowel obstruction)\n• Diaphoresis, insensible losses in febrile patients\n• Cerebral salt wasting (post-neurosurgery)\n\n**Management:**\n• **Normal saline (0.9% NaCl)** for volume resuscitation — NS is hypertonic relative to the patient’s serum in severe hyponatremia\n• Replace ongoing losses (NG output, drain output)\n• Correct potassium and magnesium\n\n**HIGH overcorrection risk.** Once euvolemia is restored, ADH suppresses abruptly. The kidney suddenly excretes a large volume of dilute urine ("aquaresis"), and Na+ can rise 15-20 mEq/L in hours.\n\n• **If Na+ <120:** Proactive [Desmopressin (DDAVP)](#/drug/desmopressin/ddavp clamp) clamp before volume resuscitation\n• Watch for sudden increase in urine output — this signals ADH suppression and imminent rapid Na+ rise\n• Check Na+ every 2 hours during resuscitation\n• [Overcorrection Rescue Protocol](#/info/na-overcorrection) at bedside' WHERE id = 'na-hypo-hypovolemic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Edematous states with reduced effective arterial blood volume** trigger ADH release despite total body water excess.\n\n**Causes:**\n• **Heart failure** — poor forward flow → baroreceptor-mediated ADH release\n• **Cirrhosis** — splanchnic vasodilation → reduced effective arterial volume\n• **Nephrotic syndrome** — hypoalbuminemia → reduced oncotic pressure\n\n**Management:**\n• **Fluid restriction** 1-1.5 L/day (first-line for all three)\n• [Furosemide](#/drug/furosemide/hypernatremia) **20-40 mg IV** for diuresis — loop diuretics produce dilute urine and help correct Na+\n• Treat the underlying condition (guideline-directed HF therapy, TIPS for cirrhosis)\n• **Sodium restriction** <2g/day\n\n**Avoid:**\n• Normal saline — worsens total body sodium and edema\n• Hypertonic saline — only if severe symptoms (seizures/coma), and only as temporizing bolus\n• Vaptans — unpredictable overcorrection, hepatotoxicity, no mortality benefit\n\n**Prognosis:** Hyponatremia in HF and cirrhosis is an independent marker of disease severity and mortality.' WHERE id = 'na-hypo-hypervolemic' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Ongoing monitoring during hyponatremia treatment.**\n\n**Active correction (Na+ <125 or symptomatic):**\n• Check Na+ every **2 hours**\n• Plot correction trajectory on flow sheet\n• Track all IV fluids, PO intake, and urine output\n• I&O catheter for accurate urine measurement\n\n**Stable/improving (Na+ 125-130):**\n• Check Na+ every **4-6 hours**\n• Continue fluid restriction or treatment of underlying cause\n\n**ICU admission criteria:**\n• Na+ <120 mEq/L\n• Active DDAVP clamp in progress\n• Severe neurological symptoms\n• Active overcorrection requiring D5W infusion\n• Receiving hypertonic saline\n\n**Step-down from ICU:**\n• Na+ >125 and stable uptrend\n• DDAVP clamp successfully discontinued\n• Underlying cause addressed\n\n**Discharge criteria:**\n• Na+ >130 mEq/L and stable\n• Underlying cause treated or managed\n• Outpatient follow-up with repeat Na+ in 1-2 weeks' WHERE id = 'na-hypo-monitoring' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'Hypernatremia (Na+ >145 mEq/L) is **almost always a free water deficit** — either inadequate intake or excessive loss. Rarely, it results from sodium gain.\n\n**Assess volume status and urine output:**\n\n**Volume depleted (most common):**\n• Inadequate water intake (altered mental status, intubated, elderly, infant)\n• GI losses + inadequate replacement\n• Insensible losses (fever, burns, mechanical ventilation)\n• Diuretic use without free water replacement\n\n**Polyuria (>3 L/day):**\n• Diabetes insipidus (central or nephrogenic)\n• Osmotic diuresis (hyperglycemia, mannitol, urea)\n• Post-obstructive diuresis\n\n**Volume overloaded (iatrogenic):**\n• Excessive hypertonic saline, NaHCO₃, or high-Na medications\n• Excess NS resuscitation with inadequate free water\n\n[Hypernatremia Causes](#/info/na-hyper-causes) — 7-category breakdown of all etiologies' WHERE id = 'na-hyper-assess' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Polyuria with dilute urine (Urine Osm <300 mOsm/kg) suggests diabetes insipidus.**\n\n**Central DI** — deficient ADH production:\n• Post-neurosurgery (pituitary), head trauma, brain death\n• Tumors (craniopharyngioma, metastases)\n• Autoimmune hypophysitis\n• **Diagnostic clue:** Urine Osm rises >50% after DDAVP 2 mcg IV trial\n\n**Nephrogenic DI** — kidney resistant to ADH:\n• Lithium (most common medication cause — up to 40% of long-term users)\n• Hypercalcemia, hypokalemia\n• Sickle cell disease, amyloidosis\n• Pregnancy (placental vasopressinase)\n• **Diagnostic clue:** Urine Osm does NOT rise after DDAVP trial\n\n**DDAVP trial interpretation:**\n• Give DDAVP 2 mcg IV, measure urine Osm at 0 and 2 hours\n• >50% rise → central DI (kidney responds to exogenous ADH)\n• <50% rise → nephrogenic DI (kidney does not respond)' WHERE id = 'na-hyper-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Replace ADH with DDAVP + replace free water deficit.**\n\n**DDAVP replacement:**\n[Desmopressin (DDAVP)](#/drug/desmopressin/central diabetes insipidus) **2 mcg IV q8-12h** (acute inpatient) OR **10 mcg intranasal BID** (stable/outpatient)\n\n**Free water replacement:** Calculate deficit and replace (see next step).\n\n**Post-neurosurgical DI:**\n• Often a **triphasic response:**\n  1. DI phase (days 1-5): polyuria, rising Na+\n  2. SIAD phase (days 5-10): oliguria, falling Na+ (uncontrolled ADH release from dying neurons)\n  3. Permanent DI (if >80% of neurons destroyed)\n• **Critical:** Monitor Na+ closely during transitions — do NOT continue DDAVP blindly into the SIAD phase (will cause dangerous hyponatremia)\n• Check urine output and Na+ q4-6h in the first 2 weeks post-surgery\n\n**Brain death evaluation:** Central DI with polyuria is a supportive finding but not diagnostic alone. If urine output >300 mL/hr with urine Osm <200, strongly suggestive.' WHERE id = 'na-hyper-central-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**The kidney does not respond to ADH — DDAVP is ineffective.** Treatment relies on reducing solute load and using pharmacologic tricks.\n\n**Step 1 — Remove the offending agent:**\n• **Lithium** — discuss with psychiatry before discontinuing. Amiloride 5-10 mg BID blocks lithium entry into collecting duct cells (partially protective even if lithium continued)\n• **Hypercalcemia** — treat aggressively (IV saline, calcitonin, bisphosphonates)\n• **Hypokalemia** — correct to >3.5 mEq/L\n\n**Step 2 — Thiazide paradox:**\n• Thiazide diuretic (HCTZ 25 mg daily) + amiloride 5 mg BID\n• **Paradoxical antidiuresis** — thiazides cause mild volume depletion → increased proximal tubular reabsorption → less water delivered to diluting segment → less urine output\n• Combined with low-sodium diet (<2g/day) to enhance the effect\n\n**Step 3 — Large free water volumes:**\n• Patients may require **10-20 liters/day** of free water intake to keep up with urinary losses\n• If unable to drink enough: D5W IV to match urine output + ongoing losses\n• Enteral free water via NG/OG tube if intubated\n\n**NSAIDs** (indomethacin 50 mg TID) can reduce urine output by 25-50% but GI/renal toxicity limits long-term use.' WHERE id = 'na-hyper-nephrogenic-di' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Calculate the free water deficit (FWD) to guide replacement volume.**\n\n**Formula:** FWD (liters) = TBW × [(Na/140) - 1]\n• TBW = weight (kg) × 0.6 (men) or × 0.5 (women/elderly)\n• Example: 70 kg male, Na+ 160 → TBW = 42L, FWD = 42 × (160/140 - 1) = **6.0 liters**\n\n**The FWD formula underestimates true deficit** — it does not account for ongoing losses (insensible, urinary, GI). Add ~1-1.5 L/day for ongoing losses.\n\n**Fluid choice (order of preference):**\n1. **Enteral free water** (PO or NG/OG tube) — safest, most physiologic\n2. **D5W IV** — if NPO or insufficient enteral intake (D5W = free water once glucose is metabolized)\n3. **0.45% NaCl** — only half is free water; use if concurrent volume depletion\n\n**Correction rate:**\n• **Acute hypernatremia (<48 hours):** Can correct 1 mEq/L/hr safely\n• **Chronic hypernatremia (>48 hours or unknown):** Maximum **10-12 mEq/L per 24 hours** — rapid correction risks cerebral edema\n• Most hypernatremia in hospitalized patients is chronic → correct slowly\n\n**Replace the deficit over 48-72 hours** — not in a single bolus. Divide calculated free water evenly.\n\n**Address the underlying cause simultaneously** — free water alone does not fix DI, ongoing GI losses, or medication causes.' WHERE id = 'na-hyper-fwd' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Iatrogenic hypernatremia from excessive sodium administration** is increasingly common in ICU patients receiving NS boluses, NaHCO₃, and high-sodium medications.\n\n**Causes:**\n• Large-volume NS resuscitation without free water\n• NaHCO₃ infusions (isotonic bicarb = 150 mEq Na/L)\n• High-sodium medications (piperacillin-tazobactam = 4.7 mEq Na per gram)\n• Hypertonic saline overcorrection during hyponatremia treatment\n\n**Management — natriuretic diuresis + free water:**\n• [Furosemide](#/drug/furosemide/hypernatremia) **20-40 mg IV** — produces hypotonic urine (Na+ ~75 mEq/L), removing more sodium than water\n• Replace urine volume with **D5W or enteral free water** to lower Na+ while diuresing excess sodium\n• Thiazide + amiloride if loop diuretic insufficient\n\n**Target:** Negative sodium balance (remove more Na+ than you give) while maintaining neutral or positive water balance.\n\n**Switch IV fluids** from NS to D5W or 0.45% NaCl for maintenance. Review all sodium-containing medications and minimize where possible.\n\n**Monitor:** Na+ every 4-6 hours. Strict I&O. Daily weights.' WHERE id = 'na-hyper-overload' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Ongoing monitoring during hypernatremia treatment.**\n\n**Active correction:**\n• Check Na+ every **4-6 hours**\n• Strict intake and output (I&O catheter recommended)\n• Daily weights\n• Monitor for signs of cerebral edema during correction (headache, confusion, seizures)\n\n**Correction targets:**\n• Chronic: maximum 10-12 mEq/L decrease in 24 hours\n• Acute (<48h): can correct 1 mEq/L/hr\n• Target Na+ 140-145 mEq/L\n\n**Overcorrection is RARE in hypernatremia** (unlike hyponatremia). Cerebral edema from overcorrection is theoretical but reported only in aggressive pediatric correction.\n\n**ICU admission criteria:**\n• Na+ >160 mEq/L\n• Hemodynamic instability\n• Active DI with massive polyuria\n• Unable to maintain adequate free water intake\n\n**Hospital-acquired hypernatremia** (Na+ develops during admission) carries mortality up to 40-60% in ICU patients — reflects severity of underlying illness, not sodium toxicity per se.\n\n[Hypernatremia in the Elderly](#/node/na-hyper-elderly) — special considerations for geriatric patients' WHERE id = 'na-hyper-monitoring' AND tree_id = 'sodium';
UPDATE decision_nodes SET body = E'**Hypernatremia in elderly patients is almost always chronic and related to impaired thirst or access to water.**\n\n**Why the elderly are vulnerable:**\n• **Diminished thirst** — aging blunts the thirst response to hypertonicity\n• **Reduced total body water** — TBW factor ~0.45-0.50 (vs 0.60 in younger adults)\n• **Impaired renal concentrating ability** — maximum urine Osm declines with age\n• **Functional limitations** — dementia, immobility, dependence on caregivers for water access\n• **Medications** — diuretics, lithium, laxatives\n\n**Key management differences:**\n• **Usually chronic** → correct slowly (max 10-12 mEq/L/day)\n• **Oral water first** if patient can swallow safely — 200-300 mL PO every 2-4 hours\n• If unable to drink: **D5W IV** or enteral free water via NG tube\n• **ICU is usually NOT needed** unless Na+ >160 or hemodynamically unstable\n• Avoid overdiuresis — elderly have limited renal reserve\n\n**Discharge planning is critical:**\n• Ensure caregivers provide regular water access\n• Set water intake schedule (not reliant on patient requesting water)\n• Review and minimize diuretics\n• Follow-up Na+ in 1 week' WHERE id = 'na-hyper-elderly' AND tree_id = 'sodium';
-- === splinting (16 nodes) ===
UPDATE decision_nodes SET body = E'[General Splinting Principles](#/info/splint-principles) — materials, padding, technique, neurovascular checks.\n[Quick Reference Table](#/info/splint-summary) — all fractures → splint types at a glance.\n\n**Select a body region:**' WHERE id = 'splint-start' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Proximal humerus** → Sling / cuff and collar [9][10]\n• **Humeral shaft** → Coaptation splint (→ functional brace at 1–2 weeks) [7][8]\n• **Supracondylar (adult)** → Long arm posterior splint or double sugar tong [3][6]' WHERE id = 'splint-humerus' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Proximal humerus fracture (non-displaced or minimally displaced)\n• Greater tuberosity fracture\n• Shoulder dislocation post-reduction\n\n**MATERIALS**\n• Standard triangular arm sling OR cuff and collar\n• Swathe (elastic bandage around torso) for added stability if needed\n\n**APPLICATION**\n1. Arm rests in sling with elbow at 90° flexion\n2. Forearm supported across the body\n3. Wrist should be neutral (not dangling)\n4. If swathe used: wrap elastic bandage around upper arm and torso to prevent arm abduction\n\n**POSITION**\n• Elbow at 90°, arm adducted against the body\n• Allow gentle pendulum exercises (Codman exercises) after 1–2 days to prevent shoulder stiffness\n\n**PEARLS**\n• PROFHER trial (2015): sling alone is equivalent to surgery for most displaced proximal humerus fractures in adults [9]\n• Ensure padding under axilla if swathe is used — prevents skin breakdown\n• Avoid prolonged full immobilization (>2 weeks) — frozen shoulder risk\n• No imaging needed for isolated greater tuberosity fractures with <5mm displacement' WHERE id = 'splint-sling' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Humeral shaft fracture (midshaft diaphyseal)\n• Initial stabilization before functional bracing\n\n**MATERIALS**\n• 6-inch plaster or fiberglass (10–12 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n• Arm sling\n\n**APPLICATION**\n1. Measure from axilla, down medial arm, around the elbow, back up lateral arm to the deltoid insertion (U-shape)\n2. Apply stockinette and Webril padding — **extra padding in axilla and over olecranon**\n3. Dip plaster in lukewarm water, squeeze excess, apply in U-shape\n4. Mold plaster snugly around medial arm, elbow, and lateral arm\n5. Secure with elastic bandage — wrap distally to proximally\n6. Place arm in sling with elbow at 90°\n\n**POSITION**\n• Elbow at 90° flexion\n• Arm adducted against torso\n• Forearm in neutral rotation\n\n**TRANSITION TO FUNCTIONAL BRACE**\nAt 1–2 weeks: convert to a prefabricated humeral functional brace. Sarmiento (2000): 98% union rate with functional bracing, mean angulation <8° [8]. FISH trial (2020): functional bracing was non-inferior to surgery for closed humeral shaft fractures [7].\n\n**PEARLS**\n• Do NOT wrap plaster circumferentially — this is a splint, not a cast\n• The U-shape provides medial-lateral stability while allowing swelling\n• A common mistake: splint too short — must extend well above the fracture\n• Check radial nerve function before and after application (wrist drop = radial nerve palsy)' WHERE id = 'splint-coaptation' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Supracondylar fracture (adult)\n• Olecranon fracture (non-operative)\n• Coronoid fracture\n• Proximal radius/ulna fracture\n• Elbow dislocation post-reduction\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (10–12 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Measure from proximal palmar crease to mid-upper arm (posterior surface)\n2. Apply stockinette from hand to upper arm\n3. Apply Webril — **extra padding over olecranon and ulnar styloid**\n4. Apply plaster slab along posterior surface of forearm and arm\n5. Mold at the elbow to maintain 90° flexion\n6. Secure with elastic bandage — wrap distally to proximally\n7. Ensure fingers and thumb have full ROM\n\n**POSITION**\n• Elbow at 90° flexion\n• Forearm in neutral rotation (thumb pointing up)\n• Wrist in slight extension (15–20°)\n\n**PEARLS**\n• Splint should be wide enough to cover >50% of the arm circumference for stability\n• Must NOT extend past the proximal palmar crease — allow full MCP flexion\n• For supracondylar fractures: ensure the anterior humeral line bisects the capitellum on lateral x-ray post-splinting\n• Neurovascular check: median, radial, ulnar nerve function + radial pulse + capillary refill' WHERE id = 'splint-long-arm-post' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Olecranon / coronoid** → Long arm posterior splint\n• **Radius/ulna proximal or midshaft** → Long arm posterior, or double sugar tong (unstable/complex)\n• **Radius distal, isolated** → Thumb spica or volar\n• **Radius/ulna distal, complex** → Sugar tong (**A+P preferred at our institution**) [1][2]\n• **Ulna styloid** → Sugar tong (**A+P preferred**) [1][2]\n\n**INSTITUTION PREFERENCE:** A+P (anterior + posterior) splints are preferred over sugar tong for forearm and distal radius/ulna fractures. Two separate plaster slabs — no wrapping around the elbow — provides equivalent stabilization with less bulk and better patient comfort.' WHERE id = 'splint-forearm' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Distal radius and/or ulna fracture\n• Colles fracture (dorsally displaced distal radius)\n• Smith fracture (volar displaced distal radius)\n• Barton fracture\n\n**MATERIALS**\n• 4-inch plaster (10 layers)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**SUGAR TONG APPLICATION**\n1. Measure from dorsal MCP joints, around the elbow, to the palmar crease\n2. Apply stockinette and Webril — **extra padding over olecranon and both styloids**\n3. Apply plaster slab from dorsal hand, along dorsal forearm, around the flexed elbow (90°), along volar forearm to palmar crease\n4. Mold the wrist: slight flexion (10°) + ulnar deviation for Colles; neutral for Smith\n5. Secure with elastic bandage\n6. Ensure thumb and fingers remain free\n\n**A+P SPLINT ALTERNATIVE (PREFERRED)**\nInstead of wrapping around the elbow:\n1. Apply a **posterior slab** from dorsal MCP joints to proximal forearm\n2. Apply an **anterior (volar) slab** from palmar crease to proximal forearm\n3. Secure both with elastic bandage\n4. Provides equivalent AP stability without elbow restriction\n5. Better patient comfort, easier to adjust, less risk of elbow stiffness\n\n**POSITION**\n• Wrist: 10° flexion + ulnar deviation (dorsal displacement)\n• Forearm: neutral rotation\n• Elbow (sugar tong only): 90° flexion\n\n**PEARLS**\n• A+P eliminates the need to wrap around the elbow while maintaining AP stability\n• Sugar tong prevents pronation/supination — use when rotational control is critical\n• For Colles: mold the volar slab into slight flexion and ulnar deviation with 3-point pressure\n• Check capillary refill, sensation, and finger ROM after application\n\n**INSTITUTION NOTE**\nA+P splints preferred over sugar tong — no wrapping around elbow. [1][2]' WHERE id = 'splint-sugar-tong' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Supracondylar fracture with concurrent distal forearm fracture\n• Highly unstable distal radius/ulna fractures requiring rotational and AP control\n• Complex elbow fracture-dislocations (temporary stabilization)\n\n**MATERIALS**\n• 4-inch plaster (10 layers) — TWO separate slabs\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. **First slab (forearm sugar tong):** From dorsal MCP joints, along dorsal forearm, around the elbow, along volar forearm to palmar crease — identical to standard sugar tong\n2. **Second slab (arm sugar tong):** From lateral upper arm, around the elbow, to medial upper arm — provides additional medial-lateral stability at the elbow\n3. Apply stockinette and Webril before EACH slab\n4. Mold the wrist in slight flexion + ulnar deviation (if distal fracture present)\n5. Secure each slab with elastic bandage\n6. Confirm elbow at 90° flexion\n\n**POSITION**\n• Elbow at 90° flexion\n• Forearm in neutral rotation\n• Wrist in slight flexion + ulnar deviation if distal fracture present\n\n**PEARLS**\n• Provides the most stability of any splint for the upper extremity — controls AP, medial-lateral, and rotational forces\n• Bulky and uncomfortable — use only when maximum stability is required\n• Two slabs allow for swelling — safer than circumferential casting in the acute setting\n• Monitor for compartment syndrome — especially with combined fractures\n• Mark the elastic bandage layers clearly so the patient can loosen if swelling increases' WHERE id = 'splint-double-sugar-tong' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n**Carpal Bones**\n• Scaphoid, trapezium, lunate fracture → Thumb spica [3][6]\n• Lunate dislocation → Sugar tong (**A+P preferred**) [1]\n• Triquetrum, pisiform, trapezoid, capitate, hamate → Volar splint [3]\n\n**Soft Tissue**\n• UCL injury (gamekeeper/skier thumb) → Thumb spica\n• Thumb MCP dislocation → Thumb spica\n• De Quervain tenosynovitis → Thumb spica\n\n**Metacarpals**\n• 1st metacarpal (Bennett, Rolando) → Thumb spica [6]\n• 2nd / 3rd metacarpal → Radial gutter or volar [3]\n• 4th / 5th metacarpal (boxer fracture) → Ulnar gutter [3][6]\n\n**Phalanges**\n• 1st phalanx (thumb) → Thumb spica\n• 2nd / 3rd proximal or middle → Radial gutter or buddy taping\n• 4th / 5th proximal or middle → Ulnar gutter or buddy taping\n• Distal phalanx → Aluminum U-shaped (stack) splint\n\n**BUDDY TAPING:** Tape injured finger to adjacent finger with padding between. Allows protected ROM. Appropriate for stable, non-displaced proximal/middle phalanx fractures.\n\n**ALUMINUM FINGER SPLINT:** Moldable metal splint for distal phalanx fractures and mallet finger. Keep DIP in extension (stack splint). Leave PIP free.' WHERE id = 'splint-wrist-hand' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Scaphoid fracture (confirmed or suspected — snuffbox tenderness)\n• Trapezium fracture\n• Lunate fracture\n• 1st metacarpal fracture (Bennett, Rolando)\n• Thumb MCP dislocation post-reduction\n• UCL injury (gamekeeper/skier thumb)\n• De Quervain tenosynovitis\n• Isolated distal radius fracture (alternative to volar)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette (with thumb hole cut), 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Apply stockinette to hand and forearm — **cut a thumb hole**\n2. Apply Webril — **extra padding over radial styloid and 1st MCP joint**\n3. Apply plaster slab along the radial side of the forearm, wrapping around the thumb to include the first metacarpal and thumb to the IP joint\n4. Plaster extends from mid-forearm to just past the thumb IP joint\n5. Mold the plaster around the thumb in a "C" position (thumb abducted and slightly opposed, as if holding a can)\n6. Secure with elastic bandage\n7. Ensure 2nd–5th fingers have full ROM\n\n**POSITION**\n• Wrist in 15–20° extension\n• Thumb: abducted, slightly opposed (functional position)\n• Thumb IP joint included in splint (scaphoid) or free (soft tissue only)\n\n**PEARLS**\n• For suspected scaphoid fracture with negative initial x-rays: immobilize in thumb spica for 10–14 days, then repeat imaging (MRI or repeat x-ray) [3][6]\n• The "anatomical snuffbox" tenderness test has high sensitivity (~90%) but low specificity — err on the side of splinting\n• Distinguish from volar splint: thumb spica immobilizes the thumb; volar does not\n• For UCL injuries: include the thumb MCP but leave IP free to prevent stiffness' WHERE id = 'splint-thumb-spica' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Non-displaced or minimally displaced distal radius fracture\n• Triquetrum fracture (dorsal chip)\n• Pisiform, trapezoid, capitate, hamate fracture\n• 2nd / 3rd metacarpal fracture (alternative to radial gutter)\n• Carpal tunnel syndrome (night splint)\n• Wrist sprain\n• Tendon injury (initial stabilization)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Measure plaster from proximal palmar crease to mid-forearm (volar surface)\n2. Apply stockinette from hand to forearm\n3. Apply Webril — **extra padding over ulnar styloid**\n4. Apply plaster slab along volar surface of forearm\n5. Mold with gentle pressure — maintain wrist in slight extension\n6. Secure with elastic bandage — wrap distally to proximally\n7. Ensure thumb and all fingers have full ROM\n\n**POSITION**\n• Wrist in 15–20° extension (position of function)\n• Fingers free — must be able to make a full fist\n• Thumb completely free\n\n**PEARLS**\n• The simplest and most commonly applied ED splint\n• Does NOT control pronation/supination — if rotational control needed, use sugar tong or A+P\n• For buckle (torus) fractures in adults: volar splint with ortho follow-up in 1 week\n• Ensure splint does NOT extend past the proximal palmar crease — blocking MCP flexion causes finger stiffness\n• Can be converted to a short arm cast at follow-up if needed' WHERE id = 'splint-volar' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• 4th metacarpal fracture\n• 5th metacarpal fracture (boxer fracture)\n• 4th / 5th proximal phalanx fracture\n• 4th / 5th middle phalanx fracture (non-displaced)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n• Finger separator padding (cotton between 3rd and 4th fingers)\n\n**APPLICATION**\n1. Place cotton padding between 3rd and 4th fingers\n2. Apply stockinette from fingertips (4th and 5th digits) to mid-forearm\n3. Apply Webril — **extra padding over ulnar styloid and 5th MCP**\n4. Apply plaster slab along the ulnar side of the forearm and hand, extending from mid-forearm to the fingertips of the 4th and 5th digits\n5. Mold the plaster around the ulnar border of the hand\n6. Ensure the MCP joints are in **70–90° flexion** (critical!)\n7. IP joints in slight flexion (10–20°) or comfortable position\n8. Secure with elastic bandage\n\n**POSITION**\n• Wrist in 20–30° extension\n• **MCP joints at 70–90° flexion** — this is the most important positioning element\n• IP joints in slight flexion\n\n**WHY 70–90° MCP FLEXION?**\nThe collateral ligaments of the MCP joints are taut in flexion and lax in extension. Immobilizing in extension allows the ligaments to shorten → permanent MCP stiffness ("intrinsic minus" hand). [3][6]\n\n**PEARLS**\n• Boxer fractures (5th MC neck) with <40° angulation and no rotational deformity: ulnar gutter splint with ortho follow-up [6]\n• Always check for rotational malignment: have the patient flex fingers into a fist — all fingertips should point toward the scaphoid tubercle\n• The "fight bite" rule: ANY laceration over the MCP from a punch is an open joint until proven otherwise → irrigate, antibiotics, hand surgery consult\n• 3rd finger should be left free when possible to improve function' WHERE id = 'splint-ulnar-gutter' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• 2nd metacarpal fracture\n• 3rd metacarpal fracture\n• 2nd / 3rd proximal phalanx fracture\n• 2nd / 3rd middle phalanx fracture (non-displaced)\n\n**MATERIALS**\n• 4-inch plaster or fiberglass (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n• Finger separator padding (cotton between 3rd and 4th fingers)\n\n**APPLICATION**\nMirror image of the ulnar gutter splint, applied to the radial side:\n1. Place cotton padding between 3rd and 4th fingers\n2. Apply stockinette from fingertips (2nd and 3rd digits) to mid-forearm\n3. Apply Webril — **extra padding over radial styloid and 2nd MCP**\n4. Apply plaster slab along the radial side of the forearm and hand, extending from mid-forearm to the fingertips of the 2nd and 3rd digits\n5. Mold plaster around the radial border of the hand\n6. Ensure MCP joints at **70–90° flexion**\n7. IP joints in slight flexion (10–20°)\n8. Secure with elastic bandage\n\n**POSITION**\n• Wrist in 20–30° extension\n• **MCP joints at 70–90° flexion**\n• IP joints in slight flexion\n\n**PEARLS**\n• Same principles as ulnar gutter — MCP flexion is critical to prevent collateral ligament contracture\n• Always check for rotational malignment before splinting\n• 2nd and 3rd metacarpal fractures tolerate LESS angulation than 4th/5th (more rigid carpometacarpal joints)\n• If 2nd or 3rd MC is significantly angulated (>10°) → ortho referral, may need operative fixation\n• Can also use a volar splint for non-displaced 2nd/3rd MC fractures if gutter splint is not available' WHERE id = 'splint-radial-gutter' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**FRACTURE → SPLINT GUIDE**\n\n• **Distal tibia or distal fibula** → Posterior short leg (± stirrup for added stability) [3][6]\n• **Ankle sprain grade 2/3** → Stirrup splint [3]\n• **Talus, calcaneus, navicular, cuboid, cuneiform** → Posterior short leg [3][6]\n• **Metatarsal (2nd–5th)** → Posterior short leg or hard-soled shoe [3]\n• **Lisfranc** → Posterior short leg (non-weight bearing, ortho follow-up) [6]\n\n**5th METATARSAL SPECIAL CASES:**\n• Zone 1 (tuberosity/pseudo-Jones) → Hard-soled shoe, weight bear as tolerated\n• Zone 2 (Jones fracture, metaphyseal-diaphyseal junction) → Posterior short leg, non-weight bearing, ortho follow-up (high nonunion risk)\n• Zone 3 (shaft stress fracture) → Posterior short leg, non-weight bearing' WHERE id = 'splint-lower-ext' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Distal tibia fracture (non-operative)\n• Distal fibula (lateral malleolus) fracture\n• Bimalleolar / trimalleolar ankle fracture (initial stabilization)\n• Talus, calcaneus, navicular, cuboid, cuneiform fracture\n• Metatarsal fracture (non-displaced)\n• Jones fracture (5th MT zone 2)\n• Lisfranc injury\n• Achilles tendon rupture (initial, with ankle in plantarflexion)\n\n**MATERIALS**\n• 6-inch plaster (12–15 layers for adults)\n• Stockinette, 3–4 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Patient prone with knee flexed to 90° (foot accessible) or seated with foot hanging off stretcher\n2. Apply stockinette from toes to mid-calf\n3. Apply Webril — **extra padding over malleoli, calcaneus, and Achilles tendon**\n4. Measure plaster from toe base to just below the knee on the posterior surface\n5. Dip plaster in lukewarm water, squeeze, apply along posterior leg from toes to tibial tuberosity\n6. Fold plaster at the toes to create a smooth edge and foot plate\n7. **Mold the ankle at 90° dorsiflexion** (neutral) — this is the critical position\n8. Smooth plaster with flat palms\n9. Secure with elastic bandage — start at toes, wrap proximally\n\n**POSITION**\n• **Ankle at 90° (neutral dorsiflexion)** — prevents equinus contracture\n• Subtalar joint in neutral (not inverted or everted)\n• Exception: Achilles rupture — 20° plantarflexion\n\n**ADDING A STIRRUP**\nFor additional medial-lateral stability (bimalleolar/trimalleolar fractures):\n• Apply a U-shaped plaster slab from medial mid-calf, under the heel, to lateral mid-calf\n• Apply over the posterior slab before elastic bandage\n\n**PEARLS**\n• This is the workhorse lower extremity ED splint — covers almost everything\n• Must extend to the toes to prevent metatarsal/forefoot fractures from shifting\n• Extra Webril over Achilles prevents pressure necrosis (a common complication)\n• Plaster slab should be wider than the posterior leg — wrap the edges around the sides for better contouring\n• Always assess: dorsalis pedis pulse, posterior tibial pulse, sensation in all foot compartments' WHERE id = 'splint-post-short-leg' AND tree_id = 'splinting';
UPDATE decision_nodes SET body = E'**INDICATIONS**\n• Ankle sprain grade 2 (moderate — partial ligament tear)\n• Ankle sprain grade 3 (severe — complete ligament tear)\n• Isolated lateral malleolus fracture (stable, non-displaced)\n• Supplemental stability for posterior short leg splint\n\n**MATERIALS**\n• 4-inch plaster (8–10 layers)\n• Stockinette, 2–3 layers Webril, elastic bandage\n\n**APPLICATION**\n1. Apply stockinette from toes to mid-calf\n2. Apply Webril — **extra padding over both malleoli**\n3. Measure plaster from medial mid-calf, under the heel, to lateral mid-calf (U-shape)\n4. Dip plaster, squeeze excess\n5. Apply U-shaped slab: medial leg → under heel → lateral leg\n6. **Mold at 90° dorsiflexion** — maintain neutral ankle position\n7. Secure with elastic bandage\n8. Toes should remain visible and mobile\n\n**POSITION**\n• Ankle at 90° (neutral dorsiflexion)\n• Subtalar joint neutral — not inverted or everted\n\n**STIRRUP ALONE vs. WITH POSTERIOR SLAB**\n• **Stirrup alone:** Grade 2/3 ankle sprains — provides medial-lateral stability while allowing some plantarflexion/dorsiflexion for early mobilization\n• **Stirrup + posterior slab:** Fractures — maximum stability, prevents all ankle motion\n\n**PEARLS**\n• For ankle sprains: stirrup alone allows early protected motion, which improves healing compared to rigid immobilization [3]\n• The U-shape prevents inversion/eversion — the mechanism of most ankle sprains\n• Air splint (Aircast) can be substituted for stable grade 2 sprains and is easier for the patient to remove for icing and exercises\n• Ottawa Ankle Rules: no splint needed if rules are negative — patients can weight-bear with support\n• Always assess: anterior drawer test, squeeze test (syndesmosis), and base of 5th metatarsal (associated fracture)' WHERE id = 'splint-stirrup' AND tree_id = 'splinting';
-- === status-epilepticus (26 nodes) ===
UPDATE decision_nodes SET body = E'[SE Steps Summary](#/info/se-summary) — time-critical escalating treatment pathway.\n\n**Status epilepticus (SE)** is defined as a seizure lasting >5 minutes or recurrent seizures without recovery between episodes.\n\nSE that persists despite first-line and second-line treatments often necessitates intubation and anesthetic infusions. Underrecognition and delays in treatment increase morbidity and mortality.\n\n**Key principle:** Benzodiazepines become less effective the longer SE persists — GABAA receptors are internalized from the cell surface during prolonged seizure activity. Early, adequate-dose treatment is critical.\n\n**Up to 30% morbidity and mortality** in adults. Etiology drives ~80% of SE-related mortality.' WHERE id = 'se-start' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Convulsive SE:** Generalized tonic-clonic activity >5 min, or recurrent seizures without recovery of consciousness between episodes.\n\n**Subtle / late SE:** After prolonged generalized seizure, motor activity may diminish — look for subtle signs: facial twitching, nystagmus, eye deviation.\n\n**Key history:** Duration of seizure activity, witnessed motor features, prior seizure history, current medications, recent drug/alcohol use, trauma, pregnancy status.\n\nPhysical exam: lateral tongue lacerations suggest seizure over syncope. Check for meningeal signs, focal neurologic deficits, signs of trauma.' WHERE id = 'se-is-this-se' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Airway:** Position in left lateral decubitus if actively seizing. Suction available. Nasopharyngeal airway if needed — do NOT use bite block or oral airway (risk of obstruction and provider injury). Do NOT attempt intubation during active tonic-clonic seizure unless airway compromise.\n\n**Breathing:** High-flow O2 via non-rebreather. Monitor SpO2 continuously. Respiratory failure can occur from seizure itself or from benzodiazepines.\n\n**Circulation:** Cardiac monitor, IV access × 2. Vital signs including temperature.\n\n**Protect from injury** — pad side rails, remove hazards. Do NOT restrain.\n\n**Start the clock** — time from seizure onset drives treatment decisions.' WHERE id = 'se-abcs' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Fingerstick glucose STAT** — hypoglycemia is a common, easily reversible seizure trigger.\n• If glucose <60 mg/dL: D50W 25 g IV (adults) or D10W 2-5 mL/kg (peds)\n\n[SE Diagnostic Workup](#/info/se-labs) — complete lab panel and imaging guide.\n\n**Priority labs:** BMP (Na, Ca, Mg, Phos), CBC, lactate, VBG, urine drug screen, serum tox, ASM levels (if on therapy), troponin, CK, pregnancy test.\n\n**Imaging:** CT head non-contrast after stabilization — evaluate for structural cause. MRI when stable.\n\n**EEG:** Order early if available — 48% of patients with altered consciousness post-SE have ongoing NCSE on EEG.\n\n**Lumbar puncture:** If signs of meningitis, fever with no clear source, or immunocompromised.' WHERE id = 'se-glucose-labs' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Route of administration determines first-line benzodiazepine choice.\n\n**IV access preferred** but should NOT delay treatment. If IV is not immediately available, give IM midazolam — the RAMPART trial showed IM midazolam is non-inferior to IV lorazepam and faster to administer.\n\nUnderdosing of benzodiazepines leads to poor response and increased likelihood of refractory SE.' WHERE id = 'se-iv-access' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Lorazepam](#/drug/lorazepam/status epilepticus) 0.1 mg/kg IV (max 4 mg/dose), push over 2 min.\n\n**May repeat once** in 5-10 minutes if seizure persists. Total max: 8 mg.\n\n**Alternative if lorazepam unavailable:**\n• [Diazepam](#/drug/diazepam/status epilepticus iv) 0.15-0.2 mg/kg IV (max 10 mg), repeat once\n\nLorazepam is preferred over diazepam — higher seizure termination rate (65% vs 56%) and longer duration of action.\n\n**Monitor for respiratory depression** — have bag-valve mask and suction at bedside. Patients who received multiple BZD doses from EMS are at higher risk.' WHERE id = 'se-iv-bzd' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Midazolam](#/drug/midazolam/status epilepticus im) 0.2 mg/kg IM (max 10 mg) into deltoid or vastus lateralis.\n\n**RAMPART trial:** IM midazolam terminated seizures in 73% vs 63% for IV lorazepam (p<.001). Faster time to treatment offset the slightly slower IM onset.\n\n**Weight-based dosing:**\n• ≥40 kg: 10 mg IM\n• 13-40 kg: 5 mg IM\n\n**Alternative routes:**\n• Intranasal midazolam: 0.2 mg/kg via mucosal atomizer (less effective than IM per Guterman et al)\n• [Diazepam](#/drug/diazepam/status epilepticus rectal) 0.2-0.5 mg/kg PR (max 20 mg) — no longer recommended as first-line\n\n**Continue attempting IV access** — will be needed for 2nd-line agents if BZD fails.' WHERE id = 'se-no-iv-bzd' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Assess **5 minutes** after BZD administration. Up to 2 doses of first-line BZD may be given.\n\nIf second dose given, reassess after 5 additional minutes.\n\n**Seizure terminated** = cessation of all motor activity AND progressive improvement in consciousness. Subtle motor signs (facial twitching, nystagmus) may indicate ongoing SE.' WHERE id = 'se-bzd-response' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Seizure terminated with first-line benzodiazepine therapy.\n\n**Post-seizure management:**\n• Monitor for recurrence — recurrence risk is significant\n• Complete diagnostic workup (labs, imaging, EEG if available)\n• Determine etiology — drives 80% of outcome\n• Consider ASM loading for seizure prophylaxis if first unprovoked seizure with high recurrence risk, known epilepsy with subtherapeutic levels, or structural lesion identified\n• [Levetiracetam](#/drug/levetiracetam/status epilepticus) 20-60 mg/kg IV (max 4500 mg) is preferred for ASM loading\n\n**If patient does not return to baseline within 30-60 min**, consider ongoing NCSE — obtain urgent EEG.' WHERE id = 'se-bzd-success' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Before selecting 2nd-line antiseizure medication, identify if the patient belongs to a special population that changes management.\n\nIf none apply, proceed directly to standard 2nd-line ASM selection.' WHERE id = 'se-special-pop' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'BZD-refractory convulsive SE. Administer within **5-10 minutes** of BZD failure.\n\n**ESETT trial (2019):** Levetiracetam, fosphenytoin, and valproate had **equivalent efficacy** (~47% seizure cessation at 60 min). No significant difference in adverse events between the three agents.\n\nChoice should be tailored to patient''s comorbidities and contraindications.\n\n[2nd-Line ASM Comparison](#/info/se-asm-comparison) — side-by-side efficacy, contraindications, and side effects.' WHERE id = 'se-2nd-line-choice' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Levetiracetam](#/drug/levetiracetam/status epilepticus) 60 mg/kg IV (max 4500 mg) over 10-15 min.\n\n**ESETT:** 47% seizure termination at 60 min (equivalent to fosphenytoin and valproate).\n\n**Advantages:**\n• No cardiac effects — no telemetry requirement during infusion\n• No hepatic metabolism — no drug interactions\n• Safe in renal impairment (dose adjust if CrCl <50)\n• Safe in pregnancy (Category C, low teratogenicity — preferred 2nd line in pregnant patients)\n• Minimal drug-drug interactions\n\n**Side effects:** Psychiatric symptoms (irritability, agitation), drowsiness. Use with caution in patients with mood disorders.' WHERE id = 'se-levetiracetam' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Valproate](#/drug/valproate/status epilepticus) 40 mg/kg IV (max 3000 mg) over 10 min.\n\n**ESETT:** 46% seizure termination at 60 min.\n\n**Contraindicated in:**\n• Pregnancy (teratogenic — neural tube defects, Category X)\n• Hepatic disease / liver failure\n• Mitochondrial disorders (Alpers syndrome — fatal hepatotoxicity)\n• Known or suspected urea cycle disorders\n• Pancreatitis\n\n**Cautions:**\n• Thrombocytopenia / coagulopathy — check platelets\n• May cause hyperammonemia — check ammonia if altered mental status persists after seizure cessation\n• Well-tolerated even with larger doses and faster rates of infusion' WHERE id = 'se-valproate' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Fosphenytoin](#/drug/fosphenytoin/status epilepticus) 20 mg PE/kg IV (max 1500 mg PE) at max rate 150 mg PE/min.\n\n**ESETT:** 45% seizure termination at 60 min.\n\n**Requires cardiac monitoring** during and for 20 min after infusion — risk of:\n• Hypotension\n• Cardiac arrhythmia (bradycardia, QT prolongation)\n• AV block\n\n**INEFFECTIVE** for drug/alcohol-induced seizures — phenytoin''s selective action on voltage-gated sodium channels is insufficient for diffuse CNS toxicity.\n\n**Contraindicated in:**\n• Sinus bradycardia, SA/AV block, Adams-Stokes syndrome\n• Decompensated heart failure\n\n**Note:** Fosphenytoin (water-soluble prodrug) is preferred over phenytoin — no risk of purple glove syndrome, can be given IM. Dosed in **PE (phenytoin equivalents)**.' WHERE id = 'se-fosphenytoin' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Assess **20 minutes** after start of infusion.\n\nIf seizure persists or recurs, this is now **refractory status epilepticus (RSE)**.\n\n~30-40% of patients fail 2nd-line therapy. As SE duration increases, GABAA receptor internalization progresses and benzodiazepine/ASM resistance increases.\n\nIf the first 2nd-line agent fails, guidelines recommend either:\n• Adding another 2nd-line ASM, OR\n• Proceeding directly to anesthetic infusions' WHERE id = 'se-2nd-line-response' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'[Phenobarbital](#/drug/phenobarbital/status epilepticus) 15-20 mg/kg IV at max rate 50-100 mg/min. Max single dose: 2000 mg.\n\n**Use when ESETT agents (levetiracetam, valproate, fosphenytoin) are unavailable** or contraindicated.\n\n**Significant risks:**\n• Respiratory depression — may precipitate need for intubation\n• Hypotension\n• Excessive sedation\n\n**Have intubation supplies ready** before administration.\n\n**Also first-line for:**\n• Neonatal seizures\n• Benzodiazepine-resistant alcohol withdrawal seizures\n\nWhen benzodiazepines are completely unavailable, phenobarbital IV 15-20 mg/kg may be used as first-line emergent therapy.' WHERE id = 'se-phenobarbital' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'Seizure terminated with 2nd-line antiseizure medication.\n\n**Critical: Monitor for NCSE** — ESETT data showed 48% of patients with altered consciousness post-SE had ongoing nonconvulsive seizures on EEG.\n\n**Post-seizure management:**\n• Continuous EEG monitoring recommended — minimum 24h\n• Continue maintenance dosing of the ASM that terminated seizure\n• Complete etiology workup (labs, imaging, LP if indicated)\n• Consider adding a second ASM for prophylaxis if high recurrence risk\n• ICU admission for close monitoring' WHERE id = 'se-2nd-success' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Refractory SE (RSE)** = failure of first-line BZD AND adequate second-line ASM.\n\nOccurs in ~30-40% of SE presentations.\n\n**Immediate actions:**\n• Secure airway with rapid sequence intubation\n• Avoid prolonged paralysis — use short-acting agent (succinylcholine preferred over rocuronium) to allow clinical seizure assessment\n• Arterial line for continuous BP monitoring\n• Central venous access for vasopressors if needed\n• **Continuous EEG monitoring — MANDATORY** (cannot assess seizure activity in paralyzed/sedated patient)\n\n[RSE Management Principles](#/info/se-rse-principles) — intubation considerations, EEG targets, weaning protocol.\n\n**Consider adding another 2nd-line ASM** (e.g., [Lacosamide](#/drug/lacosamide/status epilepticus) 200-400 mg IV) as adjunct before or concurrent with anesthetic infusion.' WHERE id = 'se-rse-prep' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Goal:** EEG seizure suppression or burst suppression for 24-48 hours before weaning attempt.\n\nNo large RCTs demonstrate clear superiority between agents. Choice based on clinical factors.\n\nAll agents require mechanical ventilation and ICU-level care.\n\n[Continuous Infusion Comparison](#/info/se-infusion-comparison) — dosing, hemodynamic effects, and unique risks for each agent.' WHERE id = 'se-rse-infusion' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Continuous EEG targets:**\n• Burst suppression (3-10 sec bursts, <50% suppression ratio)\n• OR complete seizure suppression (depending on clinical scenario)\n\n**Maintenance:** 24-48 hours of seizure suppression before first wean attempt.\n\n**Weaning protocol:**\n• Reduce infusion by 25% every 4-6 hours with continuous EEG\n• If seizures recur on wean → restart at effective dose, extend 24h, retry\n\n**Super-refractory SE (SRSE):** SE persists or recurs despite 24 hours of anesthetic therapy.\n\n**SRSE options:**\n• Switch to different anesthetic agent\n• [Lacosamide](#/drug/lacosamide/status epilepticus) as adjunct\n• Immunotherapy if autoimmune etiology suspected (IVIG, steroids, plasmapheresis)\n• Therapeutic hypothermia (32-35°C)\n• Ketogenic diet\n• Neurology and neurointensive care consultation essential\n\n**NORSE (new-onset refractory SE):** No prior seizure history, no identifiable cause. ~50% remain cryptogenic. Consider autoimmune/paraneoplastic encephalitis panel.' WHERE id = 'se-rse-monitoring' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**All SE patients require ICU admission.**\n\n**Monitoring:**\n• Continuous EEG monitoring × minimum 24-48h\n• Detect NCSE, guide treatment, monitor for recurrence\n\n**Workup to complete:**\n• MRI brain (when stable) — superior to CT for structural causes\n• LP if infectious or autoimmune etiology suspected\n• Autoimmune encephalitis panel if no clear etiology (NMDA-receptor Ab, LGI1, CASPR2)\n• ASM levels (therapeutic drug monitoring)\n\n**Maintenance ASM:**\n• Continue the agent(s) that terminated SE\n• [Levetiracetam](#/drug/levetiracetam/status epilepticus) is most commonly used for maintenance\n\n**Goals of care:** Discuss with family early if RSE/SRSE — prognosis depends primarily on underlying etiology.\n\n**Neurology consultation** for all SE patients.' WHERE id = 'se-disposition' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**First question: Is this eclampsia or epilepsy?**\n\n**Eclampsia** if: hypertension, proteinuria, edema, >20 weeks gestation, or new-onset seizure in pregnancy without prior seizure history.\n\n**Eclampsia treatment:**\n• [Magnesium Sulfate](#/drug/magnesium-sulfate/eclampsia) 4-6 g IV over 15-20 min, then 1-2 g/hr infusion\n• If seizures persist despite magnesium → benzodiazepines (lorazepam)\n• **OB consultation STAT** — consider emergent delivery\n• Fetal monitoring\n\n**Epilepsy in pregnancy (breakthrough SE):**\n• Standard BZD first-line\n• For 2nd-line: **prefer [Levetiracetam](#/drug/levetiracetam/status epilepticus)** — 89% of neurologists chose it as first-line after BZD in pregnancy\n• **AVOID [Valproate](#/drug/valproate/status epilepticus)** — teratogenic (neural tube defects), Category X\n• Fosphenytoin acceptable if needed (teratogenic risk mainly with chronic exposure, less concern for acute SE)\n• Refractory SE: midazolam or propofol infusion + consider early delivery\n\n**All pregnant patients with new seizure** should receive empiric magnesium while further workup obtained.' WHERE id = 'se-pregnancy' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**9% of SE cases are substance-induced.**\n\n**Isoniazid (INH) toxicity:**\n• [Pyridoxine (Vitamin B6)](#/drug/pyridoxine/inh toxicity) is the specific antidote\n• Dose: gram-for-gram to amount ingested, OR 5 g IV empiric if amount unknown\n• INH depletes pyridoxine → GABA synthesis fails → refractory seizures\n• Standard ASMs are ineffective without pyridoxine\n\n**Alcohol withdrawal:**\n• Benzodiazepines are first-line (high-dose may be needed)\n• [Phenobarbital](#/drug/phenobarbital/status epilepticus) is effective adjunct\n• Fosphenytoin/phenytoin INEFFECTIVE for alcohol withdrawal seizures\n\n**Sympathomimetic toxicity** (cocaine, methamphetamine, MDMA):\n• BZDs first-line\n• Avoid phenytoin\n\n**General principle:** Phenytoin/fosphenytoin is often **ineffective** for drug-induced seizures — phenytoin''s selective action on voltage-gated sodium channels cannot overcome diffuse CNS toxicity from other drug mechanisms.\n\n**Treat the underlying toxidrome** alongside seizure management.' WHERE id = 'se-substance' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Same treatment algorithm as adults** — BZD first-line, then 2nd-line ASM, then anesthetic infusions.\n\n**BZD dosing (weight-based):**\n• IV Lorazepam: 0.1 mg/kg (max 4 mg), repeat × 1\n• IM Midazolam: 13-40 kg → 5 mg; ≥40 kg → 10 mg (0.2 mg/kg, max 10 mg)\n• Rectal Diazepam: 0.2-0.5 mg/kg (max 20 mg)\n\n**2nd-line ASM:** Same agents and weight-based dosing as adults (per ESETT, which included pediatric patients).\n• EcLiPSE and ConSEPT trials confirmed levetiracetam and phenytoin are equivalent in pediatric convulsive SE\n\n**Pediatric-specific considerations:**\n• **Pyridoxine-dependent epilepsy** (age <2 yr): Give [Pyridoxine](#/drug/pyridoxine/pyridoxine dependent epilepsy) 100 mg IV if SE is refractory and no clear etiology — especially neonates with refractory seizures\n• **Febrile SE:** Most common etiology in children — workup directed at fever source\n• **Inborn errors of metabolism:** Consider in neonates/infants with unexplained SE\n• **Phenobarbital** remains first-line for neonatal seizures\n\n**Weight estimation:** <1 yr: (months × 0.5) + 3.5 kg | 1-10 yr: (years × 2) + 10 kg | >10 yr: (years × 2) + 20 kg' WHERE id = 'se-peds' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'NCSE accounts for up to **48% of patients with altered consciousness post-SE** (ESETT data).\n\n**Suspect NCSE if:**\n• Unexplained altered mental status after convulsive SE\n• Subtle motor signs: eye deviation, nystagmus, lip smacking, eyelid fluttering, myoclonus\n• Failure to return to baseline after initial seizure treatment\n• Acutely ill ICU patients (especially on neurotoxic medications: cephalosporins, methotrexate, baclofen, lithium, opioids)\n\n**Diagnosis:** Requires **EEG** — cannot diagnose clinically.\n\n[NCSE Diagnostic Criteria](#/info/se-ncse-criteria) — Salzburg criteria and BZD trial protocol.\n\n**BZD trial (diagnostic + therapeutic):**\n• Administer lorazepam 1-2 mg IV while monitoring EEG\n• Clinical AND EEG improvement → confirms NCSE diagnosis\n\n**Treatment:** Same escalating algorithm as convulsive SE (BZD → 2nd-line → anesthetic infusions), but **urgency of aggressive treatment is debated** — weigh risks of anesthetic agents and intubation against ongoing nonconvulsive seizure activity.\n\nNCSE generally has lower mortality than convulsive SE, but delay in diagnosis worsens outcomes.' WHERE id = 'se-ncse' AND tree_id = 'status-epilepticus';
UPDATE decision_nodes SET body = E'**Common SE mimics:**\n\n• **Psychogenic nonepileptic seizures (PNES):** Most common mimic. Features suggesting PNES: side-to-side head movements, pelvic thrusting, forced eye closure (seizures: eyes open), emotional outbursts, asynchronous limb movements, waxing/waning pattern, absence of postictal confusion. Video EEG is definitive.\n\n• **Syncope with myoclonus:** Brief jerking movements after loss of consciousness — self-limited, resolves when horizontal. Lasts seconds (not minutes).\n\n• **Movement disorders:** Dystonic reactions (from dopamine-blocking medications), oculogyric crisis (20-30 min, no loss of consciousness), tremor, myoclonus.\n\n• **Metabolic encephalopathy:** Uremia, hyperammonemia, hepatic encephalopathy, myxedema coma.\n\n• **Drug toxicity / intoxication:** Alcohol, delirium tremens, serotonin syndrome.\n\n• **Locked-in syndrome:** Anterior pontine infarction — appears unresponsive but conscious. Test with vertical eye movements.\n\n• **Decerebrate/decorticate posturing:** From structural brain injury — not rhythmic.\n\n**Key differentiators:**\n• Lateral tongue laceration suggests seizure over syncope\n• Lactate >2.45 mmol/L: 88% sensitivity, 87% specificity for GTC seizure vs syncope/PNES\n• Prolactin elevated 10-20 min post-seizure: 53% sensitivity, 93% specificity for convulsive SE\n\n**If uncertain, treat as SE** until effectively ruled out — delayed treatment worsens outcomes.' WHERE id = 'se-differential' AND tree_id = 'status-epilepticus';
-- === stemi (23 nodes) ===
UPDATE decision_nodes SET body = E'[STEMI Steps Summary](#/info/stemi-summary)\n\n**Obtain 12-lead ECG within 10 minutes of first medical contact.**\n\nClassic presentation: chest pain/pressure ± radiation to arms, jaw, or back, with diaphoresis, nausea/vomiting, or dyspnea.\n\n**High-risk features:**\n• Chest pain + diaphoresis = highest likelihood ratio for STEMI [1]\n• Radiation to both arms — 96% specific (but only 11% sensitive) [2]\n• 8.4% of ACS presents WITHOUT chest pain — dyspnea, diaphoresis, nausea, syncope most common [3]\n\n**STEMI is an ECG diagnosis.** Do NOT delay for troponin. A negative troponin does NOT rule out STEMI.' WHERE id = 'stemi-start' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**STEMI criteria:** New J-point elevation in ≥2 contiguous leads:\n• ≥1 mm in all leads EXCEPT V2-V3\n• V2-V3: ≥2 mm in men ≥40y, ≥2.5 mm in men <40y, ≥1.5 mm in women\n\nAlso look for reciprocal changes — [PAILS Mnemonic](#/info/stemi-reciprocal)\n\nWhat does the 12-lead ECG show?' WHERE id = 'stemi-ecg-pattern' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Immediately activate cardiac catheterization laboratory.**\n\n**Identify territory by STE distribution:**\n• **Anterior:** V1-V4 — LAD occlusion\n• **Inferior:** II, III, aVF — RCA (85%) or LCx (15%)\n• **Lateral:** I, aVL, V5, V6 — LCx occlusion\n• **Posterior:** V7-V9 STE (± V1-V3 ST depression) — LCx\n\n**If inferior STEMI:** Get right-sided leads to assess for RV involvement (→ avoid nitrates, volume-dependent)\n\nSee [Vascular Territories](#/info/stemi-vascular-territories) | [Pericarditis vs STEMI](#/info/stemi-pericarditis-diff)\n\nStart initial therapies immediately while preparing for reperfusion.' WHERE id = 'stemi-confirmed' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'ST depression in V1-V3 with upright T waves and prominent R wave suggests posterior (inferobasal) STEMI.\n\n**Obtain posterior leads V7, V8, V9:**\n• V7 — posterior axillary line at level of V6\n• V8 — tip of scapula\n• V9 — halfway between V8 and left paraspinal muscles\n\n**Diagnostic criteria:** STE ≥0.5 mm in any posterior lead (≥1 mm in men <40y has higher specificity)\n\nPosterior STEMI accounts for ~3% of acute MIs and is frequently missed. Per ESC guidelines, manage as STEMI. [7][8]' WHERE id = 'stemi-posterior' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'In LBBB or ventricular pacing, standard STEMI criteria cannot be applied. Use [Sgarbossa Criteria](#/calculator/sgarbossa) to evaluate.\n\n**Sgarbossa Criteria (any ONE positive = STEMI):**\n• Concordant STE ≥1 mm in leads with positive QRS (5 pts)\n• Concordant ST depression ≥1 mm in V1-V3 (3 pts)\n• Discordant STE ≥5 mm in leads with negative QRS (2 pts)\n\n**Modified Sgarbossa (Smith criteria):**\n• Replace 3rd criterion with ST/S ratio < −0.25\n• Significantly more accurate than original 3rd criterion [9]\n\nScore ≥3 = 98% specificity for STEMI. [10]\n\nPer 2017 ESC guidelines: LBBB + ongoing ischemic symptoms → manage as STEMI regardless of whether LBBB is old or new. [8]' WHERE id = 'stemi-lbbb' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'STE in aVR with ≥1 mm ST depression in multiple leads may suggest:\n• **Left main coronary artery** stenosis or occlusion\n• Triple vessel disease\n• Diffuse subendocardial ischemia\n\n**Important:** Only 10% of patients with this pattern have acute thrombotic coronary occlusion. [11] Clinical context is critical.\n\nAssess hemodynamic status — instability strongly favors emergent catheterization.' WHERE id = 'stemi-avr' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Obtain serial ECGs at **15- to 30-minute intervals** for the first 1–2 hours.\n\n• 8% of all STEMIs are identified only on repeat ECG [12]\n• Dynamic ST changes are expected in evolving AMI\n• Use fixed electrode positions for comparison\n\n**Consider bedside echo:** RWMA present in 93% of AMI patients (but also in 43% without AMI — sensitive but not specific) [13]\n\n**STEMI is an ECG diagnosis.** Do NOT wait for troponin to make treatment decisions. [4]\n\nSee [STEMI Mimics](#/info/stemi-mimics)' WHERE id = 'stemi-serial' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'STEMI criteria not met but ACS remains on differential.\n\n• Serial troponins q3–6h\n• Continuous cardiac monitoring\n• [Aspirin](#/drug/aspirin/acs) 162–325 mg if not already given\n• Consider anticoagulation per NSTEMI protocol\n• Consult cardiology for risk stratification\n\nSee [NSTEMI Management](#/tree/nstemi) for full NSTEMI decision pathway.' WHERE id = 'stemi-nstemi-workup' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'ST elevation identified as non-ACS etiology.\n\n**Common STEMI mimics:**\n• Pericarditis — diffuse concave STE, PR depression, no reciprocal changes\n• Hyperkalemia — peaked T waves, wide QRS, pseudo-STEMI pattern\n• Left ventricular hypertrophy — strain pattern\n• Benign early repolarization\n• Takotsubo cardiomyopathy — apical ballooning\n• Brugada syndrome\n\nSee [Pericarditis vs STEMI](#/info/stemi-pericarditis-diff)\n\nManage underlying condition appropriately.' WHERE id = 'stemi-alt-dx' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Start simultaneously with cath lab activation:\n\n**Antiplatelet:**\n• [Aspirin](#/drug/aspirin/acs) 162–325 mg chewed (if not given prehospital)\n• P2Y12 inhibitor loading — select agent next\n\n**Pain / Symptom management:**\n• [Nitroglycerin](#/drug/nitroglycerin/acs) 0.4 mg SL q5min × 3 (avoid if SBP <90, suspected RV infarct, or PDE-5 inhibitor use within 24–48h)\n• O₂ only if SpO₂ <90% — routine O₂ may INCREASE infarct size [15]\n• [Morphine](#/drug/morphine/acs) 4–8 mg IV only if refractory pain — may delay P2Y12 absorption and increase mortality [16][17]\n\n**Beta blocker:**\n• [Metoprolol](#/drug/metoprolol/acs) within 24h if no contraindications (do not need to start in ED)' WHERE id = 'stemi-initial-tx' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Load with ONE P2Y12 inhibitor before or at time of PCI. Discuss with interventional cardiologist.\n\n**[Prasugrel](#/drug/prasugrel/acs)** 60 mg loading → 10 mg daily\n• More potent platelet inhibition, lower 30-day and 1-year mortality vs clopidogrel/ticagrelor [18]\n• **CONTRAINDICATED:** prior stroke/TIA\n• **No benefit:** age >75y, weight <60 kg\n\n**[Ticagrelor](#/drug/ticagrelor/acs)** 180 mg loading → 90 mg BID\n• Fewer stent thromboses and lower death rate vs clopidogrel [19]\n• Higher stroke/ICH risk vs clopidogrel\n\n**[Clopidogrel](#/drug/clopidogrel/acs)** 600 mg loading → 75 mg daily\n• Variable metabolism (CYP2C19)\n• Use if CI to prasugrel AND ticagrelor, or high bleeding risk\n\nAll three are Class I, Level B recommendations. [5]' WHERE id = 'stemi-p2y12' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**For primary PCI:**\n• [UFH](#/drug/ufh/stemi) 70–100 units/kg IV bolus (without GP IIb/IIIa) OR 50–70 units/kg (with GP IIb/IIIa)\n• [Bivalirudin](#/drug/bivalirudin/acs) 0.75 mg/kg IV bolus then 1.75 mg/kg/hr — preferred if high bleeding risk\n\n**For fibrinolytic therapy** (minimum 48 hours):\n• [UFH](#/drug/ufh/stemi) weight-based bolus + infusion\n• [Enoxaparin](#/drug/enoxaparin/stemi) — alternative (age-adjusted dosing)\n• [Fondaparinux](#/drug/fondaparinux/stemi) 2.5 mg SC daily — alternative\n\nSee [Anticoagulation Details](#/info/stemi-anticoag-detail)' WHERE id = 'stemi-anticoag' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Primary PCI is preferred over fibrinolysis.\n\nSee [Reperfusion Decision Pathway](#/info/stemi-reperfusion-pathway)\n\n**Time targets:**\n• FMC-to-device ≤90 min at PCI-capable facility\n• FMC-to-device ≤120 min for transfer patients\n• DIDO (door-in–door-out) ≤30 min at referring hospital\n• Door-to-needle ≤30 min for fibrinolytics\n\nIs PCI available within target timeframes?' WHERE id = 'stemi-reperfusion-q' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Goal: First medical contact-to-device ≤90 minutes.**\n\n• Indicated for symptom onset <12 hours\n• Between 12–24 hours: reasonable if clinical or ECG evidence of ongoing ischemia\n• >24 hours, asymptomatic, stable: PCI NOT recommended (no benefit) [22]\n\n**Advantages over fibrinolysis:**\n• Higher infarct artery patency rates\n• Lower rates of recurrent ischemia, reinfarction, ICH, and death\n\n**Potential complications:** access site problems, contrast reactions, reperfusion arrhythmias, stent thrombosis.\n\n**Reperfusion arrhythmias** are common after successful PCI — assess next.' WHERE id = 'stemi-pci' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Goal: Total FMC-to-device ≤120 minutes. DIDO ≤30 minutes.**\n\n• Consider helicopter EMS to reduce transport time\n• Continue anticoagulation during transport\n• Prehospital cath lab activation reduces FMC-to-balloon time\n• Bypass non-PCI facilities if transport time <30 min to PCI center [5]\n\n**If transfer cannot achieve 120 min:** Switch to fibrinolytic strategy.\n\n**Cardiogenic shock or severe HF:** Transfer immediately regardless of time delay from MI onset. [5]' WHERE id = 'stemi-transfer' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Door-to-needle ≤30 minutes.** Fibrin-specific agents preferred.\n\nCheck [Fibrinolytic Contraindications](#/info/stemi-lytic-contraindications)\n\n**Agents** (see [Fibrinolytic Dosing](#/info/stemi-lytic-agents)):\n• [Tenecteplase](#/drug/tenecteplase/stemi) — single weight-based IV bolus (preferred)\n• [Alteplase](#/drug/alteplase/stemi) — accelerated 90-min regimen\n• [Reteplase](#/drug/reteplase/stemi) — 10 + 10 unit double bolus\n\n**Age >75 years:** Consider half-dose tenecteplase (reduced ICH risk) [23]\n\n**After fibrinolysis:** Transfer to PCI center. Angiography within 3–24 hours (NOT within first 2–3 hours). [5]\n\nAny contraindications to fibrinolysis?' WHERE id = 'stemi-lytics' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**After administering fibrinolytic:**\n\n**1. Anticoagulation** (minimum 48 hours):\n• [UFH](#/drug/ufh/stemi) weight-based bolus + infusion, OR\n• [Enoxaparin](#/drug/enoxaparin/stemi) (age-adjusted), OR\n• [Fondaparinux](#/drug/fondaparinux/stemi) 2.5 mg SC daily\n\n**2. Transfer** to PCI-capable center for angiography:\n• Within 3–24 hours (NOT within first 2–3 hours after lytics)\n• Rescue PCI if fibrinolysis fails (persistent symptoms/STE)\n\n**3. Monitor for reperfusion signs:**\n• Pain resolution\n• ≥50% ST-segment resolution within 60–90 min\n• Reperfusion arrhythmias (PVCs, AIVR)\n\n**AIVR** (accelerated idioventricular rhythm) — well-tolerated, self-limited. Do NOT treat with antidysrhythmics (may cause hemodynamic collapse). [24]' WHERE id = 'stemi-post-lytics' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Assess for STEMI complications:\n• **Cardiogenic shock** (5–10% of AMI) — hypotension, cool skin, AMS\n• **RV involvement** (33–50% of inferior STEMIs) — hypotension with clear lungs\n• **Reperfusion arrhythmias** — PVCs, VT, AIVR, AF, VF\n• **AV block** (7% with thrombolytics) [25]\n• **Mechanical complications** — VSD, papillary muscle rupture, free wall rupture' WHERE id = 'stemi-complications' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Cardiogenic shock complicates 5–10% of AMI. [26]\n\n**Immediate management:**\n• **PCI regardless of time from MI onset** (Class I)\n• Volume resuscitation if no pulmonary edema\n• Vasopressors to maintain coronary perfusion (norepinephrine preferred)\n• Consider mechanical circulatory support (IABP, Impella, ECMO)\n\n**Do NOT withhold vasopressors** for fear of worsening ischemia — the goal is coronary perfusion until revascularization.\n\nIf at non-PCI center: **transfer immediately regardless of time delay.**' WHERE id = 'stemi-shock' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'33–50% of inferior STEMIs involve the right ventricle. [27]\n\n**Diagnosis — get right-sided leads:**\n• STE ≥1 mm in V4R is diagnostic\n• Place V1R-V6R as mirror image of standard precordial leads\n\n**Management — volume-dependent:**\n• **AVOID nitrates** (reduce preload → hemodynamic collapse)\n• **AVOID diuretics**\n• Volume resuscitation with NS boluses (250–500 mL, reassess)\n• If hypotensive despite fluids: dobutamine or milrinone for RV support\n• Reperfusion via PCI remains the priority' WHERE id = 'stemi-rv' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'Most common reperfusion arrhythmias: PVCs, VT, AIVR, AF, VF. [24]\n\n**AIVR (Accelerated Idioventricular Rhythm):**\n• Regular wide-complex rhythm, rate 50–110 bpm\n• Usually a SIGN OF SUCCESSFUL REPERFUSION\n• Well-tolerated and self-limited\n• **Do NOT treat with antidysrhythmics** — may cause hemodynamic collapse\n• Resolves when sinus rate exceeds ventricular focus\n\n**VT/VF:** Defibrillate per ACLS protocol\n\n**AV block:** Incidence 7% with thrombolytic therapy. Manage bradycardia (atropine, transcutaneous pacing). [25]\n\n**Atrial fibrillation:** Rate control, see [A-Fib RVR](#/tree/afib-rvr) consult if needed.' WHERE id = 'stemi-arrhythmia' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**Women:**\n• Less likely to present with central chest pain [28]\n• Same risk factors and treatment as men\n• CV mortality has remained higher in women since 1980s\n\n**Elderly (>75 years):**\n• More atypical presentations (dyspnea, syncope, nausea)\n• Higher complication rate, more contraindications to reperfusion\n• Age alone is NOT a reason to withhold reperfusion [29]\n• Consider half-dose tenecteplase if fibrinolysis indicated\n\n**Cocaine-associated STEMI:**\n• PCI strongly preferred over fibrinolysis (higher ICH risk with lytics)\n• Benzodiazepines for chest pain, HR, and BP control\n• **Avoid pure beta-blockers** (unopposed alpha stimulation); consider [Labetalol](#/drug/labetalol/acs) if beta-blockade needed [30]\n\n**Post-cardiac arrest with STEMI:**\n• Early cath for sustained ROSC with STEMI or new LBBB\n• 2–3× higher favorable survival with early cath lab access [31]\n• Consider ECMO for refractory VF/pVT' WHERE id = 'stemi-special' AND tree_id = 'stemi';
UPDATE decision_nodes SET body = E'**All STEMI patients are admitted** after reperfusion (PCI or fibrinolysis).\n\n**In-hospital management:**\n• Continuous cardiac monitoring for reperfusion arrhythmias\n• [Metoprolol](#/drug/metoprolol/acs) within 24h if no CI (HR, BP permitting)\n• [Atorvastatin](#/drug/atorvastatin/acs) 80 mg (start immediately)\n• ACE inhibitor/ARB within 24h if EF ≤40%, HTN, or diabetes\n• DAPT: Aspirin 81 mg + P2Y12 inhibitor × 12 months\n\n**Goals of care discussions** should be held for elderly patients and those with severe comorbidities. DNR/POLST/advance directives do NOT necessarily preclude intervention. [29]\n\n**Cardiac rehabilitation** referral before discharge (25% reduction in CV mortality). [5]' WHERE id = 'stemi-dispo' AND tree_id = 'stemi';
-- === stroke (20 nodes) ===
UPDATE decision_nodes SET body = E'[Ischemic Stroke Steps Summary](#/info/stroke-summary) — time-critical reperfusion pathway.\n\nWe do not yet know if this is ischemic or hemorrhagic. If ICH (intracerebral hemorrhage) is highly suspicious, rule out with **CT head non-contrast** before proceeding.\n\nEstablish **last known well** time.\n\n**Immediate actions:**\n• Fingerstick glucose (only pre-tPA lab required)\n• Obtain [NIHSS (NIH Stroke Scale) score](#/calculator/nihss)\n• Establish IV access × 2\n• Activate stroke team if not already done\n• [MRI vs CT Stroke Protocol](#/info/stroke-imaging) — determine best imaging modality\n\nAll other labs (CBC, BMP, coags, troponin) should be drawn but should NOT delay thrombolysis in patients without known coagulopathy.' WHERE id = 'stroke-start' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Is a **disabling deficit** present?\n\nUse the NIHSS calculator below to score the deficit. **NIHSS >5 = disabling.**\n\nDisabling = deficit that would impair activities of daily living (e.g., limb weakness, aphasia, neglect, visual field cut, gait impairment).\n\nNondisabling = isolated minor symptoms (e.g., mild sensory change, mild dysarthria, isolated facial droop without other deficits).' WHERE id = 'stroke-deficit' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'How long since the patient was **last known well** (not time of symptom discovery)?\n\nFor wake-up strokes or unknown onset: treat as time from when last seen normal. MRI DWI-FLAIR mismatch may help identify candidates within 4.5h window.' WHERE id = 'stroke-timing' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Review [Thrombolysis Contraindications](#/info/stroke-contraindications) before proceeding.\n\n**BP requirement:** Must be <185/110 mmHg\n• [Labetalol](#/drug/labetalol) 10–20 mg IV bolus (first-line)\n• [Nicardipine](#/drug/nicardipine) 5 mg/hr IV infusion (second-line)\n\nIf BP cannot be controlled to <185/110, thrombolysis is contraindicated.\n\n**Labs:** Do NOT wait for coags unless patient is on anticoagulants or has known coagulopathy. Fingerstick glucose is the only required pre-treatment lab.' WHERE id = 'stroke-ivt-check' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Preferred:** [Tenecteplase](#/drug/tenecteplase) 0.25 mg/kg IV bolus (max 25 mg) — single dose over 5 seconds.\n\n**Alternative:** [Alteplase](#/drug/alteplase) 0.9 mg/kg IV (max 90 mg) — 10% bolus over 1 min, remainder over 60 min.\n\nTenecteplase is preferred per current guidelines due to equivalent efficacy, single bolus administration, and simpler dosing.\n\n[Patient Consent Info](#/info/stroke-consent)\n\n**Post-thrombolysis orders:**\n• BP <180/105 × 24h ([Labetalol](#/drug/labetalol) or [Nicardipine](#/drug/nicardipine))\n• Neuro checks q15min × 2h, then q30min × 6h, then q1h × 16h\n• No antithrombotics × 24h\n• No arterial/central lines, NG tube, or Foley × 24h if possible\n• Any neuro decline → emergent NCCT' WHERE id = 'stroke-ivt-treat' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Review CTA results. Is a **large vessel occlusion (LVO)** present?\n\nLVO targets for EVT:\n• ICA (internal carotid artery)\n• M1 segment of MCA (middle cerebral artery)\n• M2 (proximal) MCA — may be considered\n• Basilar artery' WHERE id = 'stroke-lvo-check' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'IVT is contraindicated. However, **EVT is NOT contraindicated by thrombolysis exclusion criteria** — patients with contraindications to IVT may still qualify for mechanical thrombectomy.\n\nObtain CTA if not already done.' WHERE id = 'stroke-no-ivt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Perfusion imaging is required to determine eligibility.\n\nSee [Stroke Imaging Guide](#/info/stroke-imaging) for details on CT perfusion and MRI protocols.\n\n**EXTEND trial criteria:**\n• DWI-FLAIR (diffusion-weighted imaging / fluid-attenuated inversion recovery) mismatch on MRI (DWI+, FLAIR− suggests <4.5h)\n• OR CT perfusion showing salvageable tissue\n• Ischemic core <70 mL\n• Penumbra/core mismatch ratio >1.2' WHERE id = 'stroke-extended-ivt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Anterior circulation (DAWN/DEFUSE-3 criteria):**\n• NIHSS ≥6\n• ICA or M1 occlusion on CTA\n• Small ischemic core on CT perfusion (<70 mL at 6–16h; <21 mL at 16–24h)\n• Large penumbra with mismatch ratio >1.8\n\n**Posterior circulation (basilar artery):**\n• NIHSS ≥10\n• Basilar artery occlusion on CTA\n• PC-ASPECTS ≥6\n• Up to 24h from onset (ATTENTION trial)' WHERE id = 'stroke-evt-window' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Endovascular thrombectomy (EVT) indicated.**\n\nGoal: arterial puncture within 60 minutes of arrival.\n\n• Bridging IVT: If within 4.5h and no IVT contraindications, administer [Tenecteplase](#/drug/tenecteplase) or [Alteplase](#/drug/alteplase) before/during transfer to angio suite — do NOT delay EVT for thrombolytic infusion to complete\n• NPO for sedation/general anesthesia\n• Continuous BP monitoring (arterial line)\n• Goal BP post-recanalization: <180/105 (same as post-IVT)\n\nHERMES meta-analysis: EVT achieved functional independence in 46% vs 27% with medical therapy alone (NNT ~5).' WHERE id = 'stroke-evt-eligible' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'>24 hours from last known well.\n\nNot a candidate for IVT or EVT. Focus on:\n• Antiplatelet initiation\n• Stroke etiology workup\n• Secondary prevention\n• Admission for neuro monitoring and rehab evaluation' WHERE id = 'stroke-late' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'NIHSS 0–5, nondisabling deficit.\n\nMRI with DWI is preferred (identifies small infarcts missed on CT).\n\n**ABCD2 Score** (TIA risk stratification):\nAge ≥60 (+1), BP ≥140/90 (+1), Clinical features: unilateral weakness (+2) or speech impairment (+1), Duration ≥60min (+2) or 10–59min (+1), Diabetes (+1).\n\nInfarct on imaging or ABCD2 ≥4 = higher risk of recurrent stroke.' WHERE id = 'stroke-minor' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Loading (Day 1):**\n• [Aspirin](#/drug/aspirin) 325 mg + [Clopidogrel](#/drug/clopidogrel) 300 mg\n\n**Maintenance:**\n• Aspirin 81 mg + Clopidogrel 75 mg daily × 21 days\n• Then single antiplatelet (either agent)\n\n**Alternative (CYP2C19 poor metabolizer):**\n• [Ticagrelor](#/drug/ticagrelor) 180 mg load + Aspirin 325 mg, then Ticagrelor 90 mg BID + Aspirin 81 mg × 30 days\n\nPOINT trial: DAPT (dual antiplatelet therapy) reduced 90-day stroke from 6.5% to 5.0% (NNT 38). Duration beyond 21 days increases bleeding without additional benefit.\n\nAlso initiate statin (high-intensity) and complete stroke workup (telemetry, echo, vascular imaging).' WHERE id = 'stroke-dapt' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'[Aspirin](#/drug/aspirin) 160–325 mg within 24–48h of symptom onset, then 81 mg daily.\n\nComplete stroke workup:\n• Telemetry / cardiac monitoring × 24h minimum\n• Echocardiogram (TTE (transthoracic); TEE (transesophageal) if suspected PFO (patent foramen ovale) or valve pathology)\n• Lipid panel → high-intensity statin\n• HbA1c\n• Extended cardiac monitoring if etiology unclear (14–30 day event recorder)' WHERE id = 'stroke-single-antiplatelet' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**BP management × 24h:**\n• Target <180/105 mmHg\n• [Labetalol](#/drug/labetalol) bolus ± infusion (first-line)\n• [Nicardipine](#/drug/nicardipine) infusion (alternative)\n• [Clevidipine](#/drug/clevidipine) (if faster titration needed)\n\n**Neuro checks protocol:**\n• Every 15 min × 2h\n• Then every 30 min × 6h\n• Then hourly × 16h\n• Any decline → emergent NCCT\n\n**Antithrombotics:**\n• NO aspirin, heparin, or anticoagulants × 24h post-thrombolysis\n• Repeat NCCT at 24h\n• If no hemorrhage: start antiplatelets' WHERE id = 'stroke-post-treatment' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**If no IVT given:**\n• [Aspirin](#/drug/aspirin) 160–325 mg within 24–48h of onset\n\n**If post-IVT:**\n• Wait 24h, obtain NCCT first\n• If no hemorrhage: start aspirin 81–325 mg\n\nConsider DAPT (aspirin + [clopidogrel](#/drug/clopidogrel)) for minor stroke with high-risk features (see minor stroke pathway).' WHERE id = 'stroke-antiplatelet-start' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'Determine stroke mechanism to guide secondary prevention.\n\n**Standard workup:**\n• Continuous telemetry (≥24h, ideally ≥48h)\n• Echocardiogram (TTE ± TEE)\n• Carotid/vertebral imaging (CTA or duplex)\n• Lipid panel, HbA1c, BMP\n• Hypercoagulability panel if age <60 and cryptogenic' WHERE id = 'stroke-etiology' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**DOAC (direct oral anticoagulant) preferred over warfarin** (unless mechanical valve or moderate-severe mitral stenosis).\n\nRecommended agents:\n• [Apixaban](#/drug/apixaban/atrial fibrillation) 5 mg BID (preferred for stroke prevention, ARISTOTLE trial)\n• [Rivaroxaban](#/drug/rivaroxaban/atrial fibrillation) 20 mg daily with food\n\n**Timing of anticoagulation initiation** (based on stroke severity):\n• TIA: 1–3 days\n• Minor stroke (NIHSS <8): 4–7 days\n• Moderate stroke (NIHSS 8–15): 7–14 days\n• Severe stroke (NIHSS >15 or large infarct): ≥14 days\n\n**Do NOT bridge with heparin** — no benefit over delayed DOAC, increases bleeding.\n\nDiscontinue antiplatelet when DOAC initiated (unless concurrent ACS/stent).' WHERE id = 'stroke-afib' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Antiplatelet:**\n• [Aspirin](#/drug/aspirin) 325 mg daily (or DAPT × 21–90 days for intracranial stenosis)\n\n**Statin:**\n• High-intensity statin (atorvastatin 40–80 mg or rosuvastatin 20–40 mg)\n• Target LDL <70 mg/dL\n\n**Carotid stenosis management:**\n• Symptomatic 70–99% stenosis: CEA (carotid endarterectomy) within 2 weeks (Class I)\n• Symptomatic 50–69%: CEA is reasonable (Class IIa)\n• CEA preferred over CAS (carotid artery stenting) for most patients\n\n**Intracranial stenosis 70–99%:**\n• DAPT (aspirin + [clopidogrel](#/drug/clopidogrel)) × 90 days\n• Then single antiplatelet\n• Aggressive risk factor management (BP <140/90, LDL <70)' WHERE id = 'stroke-atherosclerotic' AND tree_id = 'stroke';
UPDATE decision_nodes SET body = E'**Antiplatelet:**\n• [Aspirin](#/drug/aspirin) 81 mg daily\n\n**Statin:**\n• High-intensity statin regardless of baseline LDL\n\n**Blood pressure:**\n• Target <130/80 mmHg (after acute phase)\n• Initiate antihypertensive before discharge if stable\n\n**Extended cardiac monitoring:**\n• If cryptogenic: 14–30 day ambulatory cardiac monitor\n• Detects paroxysmal AF in ~12% of cryptogenic strokes\n• If AF detected: transition to anticoagulation\n\n**PFO closure:**\n• Consider if age <60, PFO with atrial septal aneurysm or large shunt, and cryptogenic stroke\n• Refer cardiology for RESPECT/CLOSE trial-based evaluation\n\n**Lifestyle:**\n• Smoking cessation\n• Exercise: moderate intensity ≥40 min, 3–4x/week\n• Mediterranean or DASH diet\n• Weight management (BMI <25)' WHERE id = 'stroke-other-prevention' AND tree_id = 'stroke';
-- === syncope (23 nodes) ===
UPDATE decision_nodes SET body = E'[Syncope Evaluation Steps Summary](#/info/syncope-summary)\n\nPatient presents with transient loss of consciousness. First priority: **exclude immediately life-threatening conditions.**\n\nAre any of the following present?\n• Persistent abnormal vital signs (hypotension, tachycardia, bradycardia, hypoxia, tachypnea)\n• Neurologic deficit or headache\n• Chest pain or dyspnea\n• Abdominal pain or pulsatile mass\n• Evidence of hemorrhage or hypovolemia' WHERE id = 'sync-start' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**TLOC with persistent abnormalities is NOT simple syncope until serious diagnoses are excluded.** [1,2]\n\nEvaluate based on clinical findings:\n• Hypotension + tachycardia → hemorrhage, PE, sepsis, AAA\n• Chest pain → ACS, aortic dissection, PE, tension pneumothorax\n• Headache + neuro deficit → SAH, stroke, ICH\n• Abdominal pain → ruptured AAA, ectopic pregnancy\n• Hypoxia + tachypnea → PE, pneumothorax\n• Persistent bradycardia → high-grade AV block, sick sinus\n\nObtain ECG, targeted labs, and imaging as indicated. **Do not diagnose syncope until life-threatening causes are excluded.**' WHERE id = 'sync-life-threat' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Bystanders often call any convulsive activity a "seizure." **Syncope commonly causes myoclonic jerks** (especially if patient cannot lie flat). [4,5]\n\n**Features favoring seizure:**\n• Prolonged postictal disorientation (>few seconds)\n• Tongue laceration (lateral)\n• Head-turning, unusual posturing\n• >20 rhythmic jerks\n\n**Features favoring syncope:**\n• Presyncope (lightheadedness, diaphoresis, palpitations)\n• Loss of consciousness with prolonged standing/sitting\n• <10 jerks, brief duration\n• Rapid return to baseline\n\nUrinary incontinence does NOT distinguish between seizure and syncope. [6]\n\nDoes the clinical picture suggest seizure?' WHERE id = 'sync-true-syncope' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Clinical features suggest **seizure rather than syncope.** Evaluate and manage per seizure pathway.\n\n**Pearl:** Elevated serum lactate within 2 hours of the event is superior to CK for distinguishing seizure from syncope (positive LR 5.8). [7]\n\nIf seizure is excluded after further workup, return to syncope evaluation.' WHERE id = 'sync-seizure' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**ECG is mandatory for ALL syncope patients** — even those with suspected vasovagal syncope. [1,2]\n\nPlace on continuous telemetry. In low-risk patients, 50% of arrhythmic causes are detected within 2 hours; 6 hours for medium/high-risk. [8]\n\nReview ECG carefully for:\n• Nonsinus rhythm or significant ectopy\n• Conduction abnormalities (AV block, BBB, pre-excitation)\n• QTc prolongation (>460 ms concerning, >500 ms high-risk)\n• ST changes or Q waves suggesting ischemia\n• [High-risk ECG patterns](#/info/syncope-ecg) (Brugada, HCM, epsilon waves)\n\nIs the ECG abnormal?' WHERE id = 'sync-ecg' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Abnormal ECG is a high-risk feature in all syncope risk stratification tools.** [1,2,10]\n\nECG findings associated with serious cardiac arrhythmias within 30 days: [9]\n• Nonsinus rhythm\n• Mobitz II or third-degree AV block\n• Bundle branch block (especially new LBBB)\n• QTc >460 ms\n• Pre-excitation (WPW)\n• Brugada type 1 pattern\n• Epsilon waves (ARVC)\n• "Dagger" Q waves (HCM)\n• ST depression or T-wave inversions\n\nAtrial fibrillation, IVCD, LVH, and ventricular pacing are independent predictors of mortality. [11]\n\nContinue to history assessment — ECG findings will factor into risk stratification.' WHERE id = 'sync-abnormal-ecg' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**The history is the single most important tool** in identifying the cause of syncope. [1,2]\n\n[Historical Features by Etiology](#/info/syncope-history-features)\n\nAssess:\n• **Activity at onset:** position, exertion, triggers (pain, blood, emotional)\n• **Prodrome:** nausea, sweating, lightheadedness, palpitations, tunnel vision\n• **During event:** duration, witnessed movements, skin color\n• **After event:** orientation, confusion duration, injuries\n• **Prior episodes:** recurrent? same triggers? prior workup?\n• **Medications:** new or changed? antihypertensives, QT-prolonging drugs?\n• **Cardiac history:** heart failure, CAD, valvular disease, prior arrhythmia?\n• **Family history:** sudden cardiac death, drowning, unexplained MVCs in young relatives?\n\nDoes the history suggest a **clear benign etiology** (vasovagal, situational, orthostatic)?' WHERE id = 'sync-history' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Labs are low-yield unless directed by history/exam.** [1,2]\n\nConsider in patients without clear benign diagnosis:\n• **CBC** — anemia (but initial Hgb may be normal in acute hemorrhage)\n• **BMP** — electrolytes, renal function, glucose\n• **Pregnancy test** — all women of childbearing age\n• **Troponin (hs-cTnT)** — elevated troponin is an independent predictor of 30-day mortality [13]\n• **BNP/NT-proBNP** — elevated BNP confers ~8× increased risk of serious outcomes; may distinguish cardiac from vasovagal [14,15]\n• **Lactate** — if seizure vs syncope unclear (within 2 hours)\n\n**Do NOT routinely obtain:**\n• D-dimer (unless PE otherwise suspected by PERC/Wells)\n• Head CT (unless neuro deficit or head trauma)\n• EEG (unless seizure suspected)\n• Stress testing (unless exertional syncope with ischemia concern)' WHERE id = 'sync-labs' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Most common identified cause of syncope.** Good long-term prognosis. [17,18]\n\n**Subtypes:**\n• **Vasovagal** — triggered by pain, blood, emotions, medical procedures; prodrome with nausea, sweating, warmth. More common age <40.\n• **Situational** — Valsalva, post-exercise, coughing, swallowing, defecation\n• **Carotid sinus** — head-turning, shaving (age >40)\n\n**For unexplained syncope in patients >40 years**, consider carotid sinus massage (AHA/ESC recommendation) — diagnostic in up to 60% of appropriate candidates. [19]\n\n**Recurrence:** Common but not a predictor of mortality. [20,21]\n\n**If ECG is normal** and history is classic, this is a **low-risk diagnosis.**' WHERE id = 'sync-vasovagal' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'Orthostatic hypotension = **SBP drop >20 mmHg upon standing**, or symptoms with position change. [1]\n\nMost common cause: **medications** (~40% of cases). [22]\n\n**Drug-related causes:**\n• Antihypertensives (ACEi, ARBs, beta-blockers, CCBs)\n• Diuretics\n• Alpha-blockers (tamsulosin, doxazosin)\n• Nitrates\n• Antidepressants (TCAs, MAOIs)\n• Antipsychotics\n\n**Other causes:** volume depletion, autonomic failure (diabetes, Parkinson), adrenal insufficiency\n\n**Important:** Orthostatic hypotension does NOT exclude more serious causes, especially in the elderly. One study found no difference in 30-day serious outcomes between elderly patients with normal vs abnormal orthostatic vitals. [23]\n\nIs the orthostatic hypotension clearly **medication-related or volume-related** with an otherwise reassuring workup?' WHERE id = 'sync-orthostatic' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Medication or volume-related orthostatic syncope** with otherwise reassuring evaluation.\n\n**Management:**\n• IV fluids if volume-depleted\n• Review and adjust offending medications\n• Educate on slow position changes\n• Compression stockings and increased salt/fluid intake for recurrent episodes\n• PCP follow-up for medication adjustment\n\n**Important:** In elderly patients, identifying orthostasis allows modification of fall risk factors (medications), but orthostasis alone should NOT be the sole factor in risk stratification. [23,24]' WHERE id = 'sync-orthostatic-disposition' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Cardiac syncope carries the highest morbidity** of all causes. Patients with underlying cardiac disease + syncope have higher all-cause mortality. [25]\n\n**Features suggesting cardiac syncope:**\n• Syncope during exertion\n• Palpitations immediately before syncope\n• Syncope while supine\n• Syncope without prodrome (abrupt)\n• History of structural heart disease (HF, CAD, valvular)\n• Family history of sudden cardiac death or inherited arrhythmia\n• Abnormal ECG\n\n**Arrhythmias** are the most common cardiac cause — and may have resolved by ED evaluation. [1,2]\n\n**Structural causes** (PE, aortic stenosis, HCM, aortic dissection) typically persist and are more easily identified.\n\nDoes the patient have **known structural heart disease or heart failure?**' WHERE id = 'sync-cardiac-suspect' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Structural heart disease + syncope = HIGH RISK.** [1,2,25]\n\n**Recommended ED workup:**\n• Continuous telemetry monitoring (minimum 6 hours for high-risk) [8]\n• Troponin (hs-cTnT) — elevated is independent predictor of 30-day mortality [13]\n• BNP/NT-proBNP — aids in recognition of cardiac syncope [14,15]\n• Echocardiography — high yield when HF, CAD, abnormal ECG, or elevated biomarkers present [26]\n\n**Consider echocardiography** if:\n• History of heart failure\n• Coronary artery disease\n• Abnormal ECG\n• Elevated hs-cTnT or NT-proBNP\n\nOtherwise, echo has low yield for most syncope patients. [26,27]' WHERE id = 'sync-cardiac-workup' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Arrhythmias are the most common cause of cardiac syncope** — and typically resolve before ED arrival. [1,2]\n\n**Clues to arrhythmic syncope:**\n• Abrupt onset without prodrome\n• Syncope while sitting or supine\n• Palpitations preceding the event\n• Abnormal ECG (bundle branch block, prolonged QTc, pre-excitation, Brugada pattern)\n• Known cardiac device (pacemaker/ICD)\n\n**ED monitoring:**\n• Continuous telemetry — 50% of arrhythmic causes detected within 2 hours (low-risk); 6 hours (medium/high-risk) [8]\n• Consider early referral for ambulatory monitoring — higher diagnostic yield if initiated within 15 days of event [28]\n\n**If arrhythmia captured on telemetry** → manage per specific rhythm.\n\n**If no arrhythmia detected** → proceed to risk stratification for disposition.' WHERE id = 'sync-arrhythmia' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'For patients with **unexplained syncope** after history, exam, and ECG — apply risk stratification. [1,2]\n\n**Risk stratification tools** do not consistently outperform clinical judgment, but help identify high-risk features. [29,30]\n\nUse the calculators below to aid disposition:\n• **CSRS** — Canadian Syncope Risk Score (best validated, multicenter) [31,32]\n• **SFSR** — San Francisco Syncope Rule (simple binary screening) [33]\n\n[Syncope Differential Diagnosis](#/info/syncope-ddx)\n\nDoes the patient have **any high-risk features?**\n\n**High-risk (ESC):** [2]\n• Major structural or coronary artery disease\n• Clinical or ECG features suggesting arrhythmic syncope\n• Syncope causing severe injury\n• Important comorbidities (severe anemia, electrolyte disturbance)' WHERE id = 'sync-risk-stratify' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Approach mirrors adults.** History, exam, and ECG are the most useful components. [34]\n\n**80% of pediatric syncope is neurally mediated** — vast majority have benign etiology. Most cardiac syncope can be diagnosed by history, exam, and ECG. [34]\n\n**Features suggesting cardiac cause in children:**\n• Exertional syncope\n• Syncope without prodrome\n• Syncope while supine\n• Family history of sudden cardiac death\n• Syncope associated with a loud noise → evaluate for **long QT syndrome** [35]\n\n**Common problem:** Excessive testing in pediatric syncope — one study found 58% received head CT with very low yield. 10% are admitted, but very few ultimately diagnosed with cardiac syncope. [36]\n\n**Bottom line:** Unless cardiac features are present, pediatric syncope can be managed conservatively with ECG and PCP follow-up.' WHERE id = 'sync-pediatric' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Particularly challenging** — many present with unexplained falls rather than syncope. [37,38]\n\n**Key points:**\n• 25-50% of unexplained falls in elderly may be syncope-related [37,39]\n• Almost half of elderly with dementia referred for unexplained falls receive a syncope diagnosis [40]\n• Neurally mediated syncope is still common in this age group [37]\n• QTc prolongation occurs in 25% of elderly — QTc >500 ms predicts 30-day and 1-year mortality [41,42]\n\n**Hospitalization controversy:**\n• Older adults often have multiple risk factors and worse outcomes overall\n• However, for unexplained syncope WITHOUT a serious ED diagnosis, **hospitalization does not improve 30-day adverse outcomes** [43]\n• Age >65 alone and unexplained syncope are NOT independent predictors of mortality [44,45]\n• Mortality is related primarily to **underlying comorbidities**, not the syncope itself [43,46]\n\nHospitalization may increase likelihood of identifying a serious diagnosis, but does not appear to improve mortality.' WHERE id = 'sync-elderly' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Hospital admission or observation unit recommended.** [1,2]\n\n**Indications for admission:**\n• Sustained or symptomatic ventricular tachycardia\n• Symptomatic conduction system disease or high-grade AV block\n• Symptomatic bradycardia or sinus pauses (not reflex-mediated)\n• Symptomatic SVT\n• Pacemaker/ICD malfunction\n• Inheritable cardiovascular conditions predisposing to arrhythmias\n• Cardiac ischemia\n• Severe aortic stenosis\n• Cardiac tamponade\n• Hypertrophic cardiomyopathy\n• Aortic dissection\n• Pulmonary embolism\n• Significant hemorrhage\n\n**Monitoring:**\n• Continuous telemetry\n• Cardiology consultation\n• Echocardiography if not already obtained\n• Consider electrophysiology referral' WHERE id = 'sync-disposition-high' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Shared decision-making recommended.** [1,2]\n\n**Intermediate-risk factors:** [1]\n• Age ≥50 years\n• Prior history of cardiac disease\n• Cardiac device without dysfunction\n• Family history of early sudden cardiac death\n• Symptoms not consistent with reflex-mediated syncope\n\n**Key point:** Patients with risk factors by PMH (CAD, HF) but with a **benign cause identified in the ED** (e.g., dehydration) may be discharged safely. [47]\n\n**If observation/discharge:**\n• Structured ED observation protocol may reduce admissions [48]\n• Ensure close follow-up (PCP, cardiology)\n• Consider referral for:\n  - Ambulatory ECG monitoring (Holter, event monitor)\n  - Tilt-table testing\n  - Implantable loop recorder\n  - Electrophysiology evaluation [1]\n\n**If admitted:**\n• Telemetry monitoring\n• Targeted workup based on risk profile' WHERE id = 'sync-disposition-intermediate' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**Low-risk patients should generally be discharged**, even with unexplained syncope. [1,2]\n\n**Low-risk features (ESC):** [2]\n• Young age with typical features of reflex syncope\n• No history of cardiac disease\n• Syncope only when standing\n• Identifiable trigger (pain, blood, prolonged standing)\n• Normal ECG\n• Normal vital signs\n\n**Discharge counseling:**\n• Explain diagnosis and expected benign prognosis\n• Counsel on avoidance of known triggers\n• Counterpressure maneuvers (leg crossing, hand gripping) for prodromal symptoms\n• Adequate hydration and salt intake\n• Review fall risk and injury prevention\n\n**Recurrence:** ~9% recurrence within 6 months; 3+ lifetime episodes most predictive of future recurrence [49]\n\n**Driving:** Be familiar with state laws regarding driving after syncope. Consider referral before return to work for commercial drivers or high-risk occupations. [50]\n\n**Follow-up:** PCP for recurrent or unexplained syncope.\n\n[Discharge Instructions](#/info/syncope-discharge) — shareable patient handout' WHERE id = 'sync-disposition-low' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**ACEP "Choosing Wisely" recommendation:** Avoid head CT in asymptomatic patients with syncope, minimal trauma, and a normal neurologic examination. [16]\n\n**Evidence:**\n• Head CT has very low yield (<0.1%) in determining the cause of syncope [51]\n• Commonly ordered despite lack of utility — one study found 58% of pediatric syncope patients received head CT [36]\n• No neurological symptoms + no head trauma + normal neuro exam = **no head CT needed** [16,51]\n\n**Only obtain head CT if:**\n• Significant head trauma from the fall\n• Neurological deficit on examination\n• Suspicion for SAH (thunderclap headache)' WHERE id = 'sync-no-head-ct' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**PE is uncommon among syncope patients.** [52,53]\n\nExisting clinical decision rules (PERC) adequately identify syncope patients with PE. [52]\n\n**Routine D-dimer is NOT indicated** in syncope patients without independent indications for PE evaluation. [54,55]\n\n**When to consider PE:**\n• Unexplained persistent tachycardia, hypotension, tachypnea, or hypoxia in ED\n• Recent surgery, immobilization, or other VTE risk factors\n• Syncope + dyspnea + pleuritic chest pain\n\n**Apply standard PE rules** (PERC → Wells → CTPA) only when clinically indicated — do NOT screen all syncope patients for PE.' WHERE id = 'sync-pe-screening' AND tree_id = 'syncope';
UPDATE decision_nodes SET body = E'**AHA and ESC recommend carotid sinus massage** in patients >40 years with undiagnosed syncope after initial evaluation. [1,2]\n\nDiagnostic in up to 60% of patients (increasing with advanced age). [19]\n\n**Positive result (carotid sinus hypersensitivity):**\n• Syncope reproduced, OR\n• Asystole >3 seconds, OR\n• AV block, OR\n• SBP drop ≥50 mmHg\n\n**Contraindications:**\n• Carotid bruit\n• Known carotid stenosis >70%\n• History of TIA or stroke within 3 months\n• MI within 3 months\n• History of VT or VF\n\n**Complication rate:** ~0.1% neurologic complications — careful patient selection is important. [56]\n\nPerform with **appropriate monitoring and resuscitation equipment** readily available.' WHERE id = 'sync-carotid-massage' AND tree_id = 'syncope';
-- === uti-peds (28 nodes) ===
UPDATE decision_nodes SET body = E'**Inclusion criteria:** Pediatric patient with suspected urinary tract infection.\n\n**UTI definition:** >50,000 CFU/mL in catheter-obtained specimen OR ≥100,000 CFU/mL in clean catch specimen, with pyuria on urinalysis.\n\n**Note — Exclusion criteria:** Immunocompromised patients, indwelling urinary catheter, known complex urologic anatomy (unless first presentation), and patients <7 days of life should be managed off-pathway with specialist consultation.' WHERE id = 'uti-start' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'This pathway applies to infants **<48 weeks postmenstrual age** and **>7 days of life** with UTI defined as >50,000 CFU/mL in catheter-obtained specimen.\n\n**Exclusion criteria:**\n• History of Candida infection (consult Infectious Disease)\n• Concomitant bacteremia or meningitis\n• >48 weeks PMA\n• <7 days of age\n\nAlter antibiotic therapy based on culture-specific antimicrobial susceptibility.\n\n**DO NOT repeat urine culture for test of cure UNLESS Candida or ESBL.**' WHERE id = 'uti-neo-dx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess probability of UTI >1%:**\n\n**Females** — 2 or more risk factors:\n• Non-Black race\n• Temperature ≥39°C\n• Fever ≥2 days duration\n• No apparent source of infection\n• Age <12 months\n\n**Males (uncircumcised):** Any febrile male — screen.\n**Males (circumcised):** 3 or more risk factors:\n• Non-Black race\n• Temperature ≥39°C\n• Fever ≥2 days duration\n• No apparent source of infection\n• Age <6 months\n\nAlso screen if: prior history of UTI or fever ≥2 days without identified source.' WHERE id = 'uti-infant-screen' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Screen all patients with:**\n• Symptoms referable to the urinary tract (dysuria, frequency, urgency, abdominal/flank pain, new incontinence)\n• Prior history of UTI with fever ≥2 days\n• Prolonged fever (≥5 days) without identified source\n\n**Collection method:** Clean catch UA with micro.\n\nInclude additional tests if STI is being considered.' WHERE id = 'uti-older-screen' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Order UA with Micro.\n\n**Collection:**\n**OPTION 1:** Catheter or suprapubic aspirate (preferred)\n**OPTION 2:** Bag specimen\n\n[UTI Definitions & Urinalysis](#/info/uti-definition-info)\n\n**Positive UA:** Leukocyte esterase OR nitrites OR microscopic WBC/bacteria.' WHERE id = 'uti-ua-cath' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Obtain clean catch urine analysis with micro.\n\nInclude additional tests if STI is being considered.\n\nIf UA positive, **must obtain catheter or clean catch specimen for culture** — bag specimens are not acceptable for culture.\n\n[UTI Definitions & Urinalysis](#/info/uti-definition-info)' WHERE id = 'uti-ua-clean' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Negative UA. Discharge with PCP or ED follow-up in 24–48 hours.\n\nClose clinical follow-up recommended. Consider alternative diagnoses for fever source.' WHERE id = 'uti-ua-neg' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**MUST be obtained from clean catch, catheter, or suprapubic aspirate.**\n\nIf bag sample was previously tested, another specimen must be obtained for culture.\n\nCase manager follow-up on culture results.' WHERE id = 'uti-culture' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess for hospital admission criteria.**\n\n**Inpatient criteria:**\n• Ill-appearing (SIRS/sepsis)\n• Dehydration requiring IV or NG fluids\n• Persistent vomiting / inability to tolerate PO antibiotics\n• Social indicators affecting compliance or follow-up\n• Failure of outpatient treatment' WHERE id = 'uti-admit-assess' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**First Line:** [Cephalexin](#/drug/cephalexin) 50 mg/kg/day divided TID–QID | Max 1 g/dose\n\n**Alternative:** [Amoxicillin-Clavulanate](#/drug/amoxicillin-clavulanate) 20–40 mg/kg/day divided BID | Max 875 mg/dose\n\n**If IgE-mediated allergy to penicillins AND cephalosporins:** [Ciprofloxacin](#/drug/ciprofloxacin) 20 mg/kg/day divided BID | Max 750 mg/dose\n\n**Medication intolerant, concern for compliance, or age <6 months:** Consider single dose [Ceftriaxone](#/drug/ceftriaxone/pediatric uti) 75 mg/kg IV or IM prior to discharge | Max 2 g/dose\n\n**Total duration:**\n• <6 months: IV + PO = **10 days**\n• ≥6 months: IV + PO = **7 days**\n\nTMP-SMX should be used with caution — only 71% susceptible among E. coli isolates.' WHERE id = 'uti-ed-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**First Line:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h | Max 2 g/dose\n\n**If IgE-mediated allergy to penicillins AND cephalosporins:** Aztreonam 90 mg/kg/day divided q8h | Max 2 g/dose, plus Gentamicin 5–7 mg/kg/day q24h\n\n**If concern for CNS involvement:** [Ceftriaxone](#/drug/ceftriaxone/pediatric uti) 100 mg/kg/day divided q12h | Max 2 g/dose\n\n**Transition criteria:** 24–48 hours of IV therapy with clinical improvement. Assess susceptibility and narrow spectrum.\n\n**Total IV + PO = 7 days.**' WHERE id = 'uti-inpatient-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Treatment is based on whether UTI is **complicated or uncomplicated**.\n\n**Complicated UTI criteria:**\n• Functional or anatomic abnormality\n• Indwelling catheter\n• Recent instrumentation\n• Recent antibiotics\n• Immunosuppression' WHERE id = 'uti-neo-abx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**IV:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h\n\n**Transition to PO** if term (by PMA), once sensitivities completed:\n[Cephalexin](#/drug/cephalexin)\n• ≤28 days of life: 75 mg/kg/day divided q8h\n• ≥29 days of life: 100 mg/kg/day divided q6h\n\n**Duration: 7 days**\n\nAlter therapy based on culture susceptibility.\n\n**DO NOT repeat urine culture for test of cure unless Candida or ESBL.**' WHERE id = 'uti-neo-rx' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Same antibiotic regimen as uncomplicated but **Duration: 10 days**.\n\n**IV:** [Cefazolin](#/drug/cefazolin) 50 mg/kg/day divided q8h\n\n**Transition to PO:**\n[Cephalexin](#/drug/cephalexin)\n• ≤28 days of life: 75 mg/kg/day divided q8h\n• ≥29 days of life: 100 mg/kg/day divided q6h\n\nAlter therapy based on culture susceptibility.\n\n**DO NOT repeat urine culture unless Candida or ESBL.**' WHERE id = 'uti-neo-rx-comp' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Obtain **renal and bladder ultrasound (RBUS)** following UTI treatment completion.\n\n*If fever persists >48 hours after start of antibiotics or unusually severe clinical illness, obtain RBUS sooner.' WHERE id = 'uti-neo-imaging' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Are any of the following present?**\n• Atypical pathogen (non-E. coli)\n• Family history of VUR or CAKUT\n• Complex clinical course\n• Any prior UTI' WHERE id = 'uti-neo-rbus-risk' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Obtain VCUG.** Obtain renal functional panel. Consult Urology. Consider Nephrology consult.\n\nPatients with **grade IV or V VUR** are at increased risk of future complications.' WHERE id = 'uti-neo-rbus-abnl' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'RBUS normal, no risk factors. Complete antibiotic course.\n\nNo further evaluation is necessary.' WHERE id = 'uti-neo-complete' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Discharge with PCP or ED follow-up in **24–48 hours**.\n\nCase manager follow-up on urine culture.\n\n**If culture positive:** Assess antibiotic susceptibility and adjust as necessary with PCP involvement.\n\n**If culture negative:** Contact PCP with results.' WHERE id = 'uti-ed-followup' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Discharge criteria:**\n• Non-toxic appearing\n• Well-hydrated\n• Can tolerate oral antibiotics and fluids\n• Normal genitourinary anatomy\n• RBUS reviewed if performed\n• Quality follow-up within 24–48 hours\n• Clinically stable for home' WHERE id = 'uti-inpatient-dc' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**RBUS criteria:**\n• Age 2–24 months with first febrile UTI\n• Children >24 months: pathogen other than E. coli, family history of renal/urologic disease, hypertension, poor growth, no improvement after 48h empiric therapy\n\n**Timing:**\n• Outpatient: order RBUS >48h of antibiotics\n• Inpatient: order after 36h (no less than 24h)' WHERE id = 'uti-imaging' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Assess for:**\n• Hydronephrosis (pelvocaliectasis)\n• Renal parenchymal loss\n• Kidney size discrepancies independent of SFU grade\n• Radiologist recommendation for further imaging' WHERE id = 'uti-rbus-result' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'**Criteria for obtaining VCUG:**\n• Hydronephrosis\n• Scarring\n• Dilated pelvis\n• Dilated ureter\n• Recommended by reviewing pediatric radiologist\n• Chronic hypertension +/- poor growth\n• Urinary pathogen other than E. coli\n• ESBL-producing E. coli' WHERE id = 'uti-vcug' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Consider Urology consult if abnormal VCUG.\n\nPatients with **grade IV or V VUR** are at increased risk of future complications.' WHERE id = 'uti-vcug-result' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'Antibiotic course complete. Ensure PCP follow-up within 24–48 hours.\n\nMonitor for recurrent UTI symptoms.' WHERE id = 'uti-complete' AND tree_id = 'uti-peds';
UPDATE decision_nodes SET body = E'UTI likelihood ≤1% based on risk factor screening.\n\nManage off-pathway with close clinical follow-up. Consider alternative diagnoses for fever source.' WHERE id = 'uti-low-risk' AND tree_id = 'uti-peds';
COMMIT;
